# eProcurement Ontology (ePO) 5.2.0.
# Source: NL2SHACL-Dataset ePO subset, commit 9e94a4e4679f9a52cd6290386f23a332de2f5ff6.
# Ontology modules are reused under EUPL 1.2; dataset descriptions are CC BY-SA 4.0.

# ---- Source module: eAccess.ttl ----
@prefix dcterms: <http://purl.org/dc/terms/> .
@prefix epo: <http://data.europa.eu/a4g/ontology#> .
@prefix org: <http://www.w3.org/ns/org#> .
@prefix owl: <http://www.w3.org/2002/07/owl#> .
@prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .
@prefix skos: <http://www.w3.org/2004/02/skos/core#> .
@prefix vann: <http://purl.org/vocab/vann/> .
@prefix xsd: <http://www.w3.org/2001/XMLSchema#> .

epo:ESPDRequest a owl:Class ;
    rdfs:isDefinedBy epo:acc ;
    rdfs:subClassOf epo:ProcurementDocument ;
    skos:definition "A document issued by a Buyer defining how the Exclusion Grounds and the Selection Criteria should be addressed in an European Single Procurement Document for a specific procurement."@en ;
    skos:historyNote "WG Approval 05/03/2024"@en ;
    skos:prefLabel "ESPD Request"@en .

epo:concernsProcedure a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:acc ;
    skos:definition "Relates to Procedure."@en ;
    skos:historyNote "WG Approval 05/03/2024"@en ;
    skos:prefLabel "concerns Procedure"@en .

epo:hasResourceType a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:acc ;
    skos:definition "Relation indicating the Resource Type."@en ;
    skos:prefLabel "has Resource Type"@en .

epo:hasSubdivision a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:acc ;
    skos:definition "Relation indicating the Subdivision."@en ;
    skos:prefLabel "has Subdivision"@en .

epo:refersToNotice a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:acc ;
    skos:definition "Reference to a Notice."@en ;
    skos:historyNote "WG approval 12/03/2024"@en ;
    skos:prefLabel "refers To Notice"@en .

epo:relatesToESPDRequest a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:acc ;
    skos:definition "Is about an European Single Procurement Document (ESPD) Request."@en ;
    skos:historyNote "WG Approval 05/03/2024"@en ;
    skos:prefLabel "relates To ESPD Request"@en .

epo:specifiesProcurementCriterion a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:acc ;
    skos:definition "Relation indicating the Procurement Criterion to be used."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "specifies Procurement Criterion"@en .

epo:acc a owl:Ontology ;
    rdfs:label "eProcurement Ontology Access - core"@en ;
    dcterms:created "2021-06-01"^^xsd:date ;
    dcterms:description "The eProcurement Ontology Access core describes the concepts and properties representing the European Public Procurement Access domain. The provision of these semantics offers the basis for a common understanding of the domain for all stakeholders ensuring the quality of data exchange and transparency. The ontology restrictions are published in a separate artefact."@en ;
    dcterms:issued "2025-10-10"^^xsd:date ;
    dcterms:license "© European Union, 2014. Unless otherwise noted, the reuse of the Ontology is authorised under the European Union Public Licence v1.2 (https://eupl.eu/)." ;
    dcterms:publisher "http://publications.europa.eu/resource/authority/corporate-body/PUBL" ;
    dcterms:title "eProcurement Ontology Access - core"@en ;
    vann:preferredNamespacePrefix "epo" ;
    vann:preferredNamespaceUri "http://data.europa.eu/a4g/ontology#" ;
    rdfs:comment "This version is automatically generated from eAccess.xml on 2025-10-10" ;
    rdfs:seeAlso <https://docs.ted.europa.eu/home/index.html>,
        <https://github.com/OP-TED/ePO/releases>,
        <https://joinup.ec.europa.eu/collection/eprocurement/solution/eprocurement-ontology/about>,
        <https://op.europa.eu/en/web/eu-vocabularies/e-procurement> ;
    owl:imports epo:core,
        epo:sub,
        <http://data.europa.eu/eli/ontology#>,
        <http://data.europa.eu/m8g/>,
        dcterms:,
        skos:,
        <http://www.w3.org/2006/time>,
        <http://www.w3.org/ns/adms>,
        <http://www.w3.org/ns/locn>,
        org:,
        <http://www.w3.org/ns/person> ;
    owl:incompatibleWith "4.2.0" ;
    owl:priorVersion "http://data.europa.eu/a4g/ontology#acc-5.1.0" ;
    owl:versionIRI epo:acc-5.2.0 ;
    owl:versionInfo "5.2.0" .



# ---- Source module: eAwarding.ttl ----
@prefix dcterms: <http://purl.org/dc/terms/> .
@prefix epo: <http://data.europa.eu/a4g/ontology#> .
@prefix org: <http://www.w3.org/ns/org#> .
@prefix owl: <http://www.w3.org/2002/07/owl#> .
@prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .
@prefix skos: <http://www.w3.org/2004/02/skos/core#> .
@prefix vann: <http://purl.org/vocab/vann/> .
@prefix xsd: <http://www.w3.org/2001/XMLSchema#> .

epo:AwardDecisionNotification a owl:Class ;
    rdfs:isDefinedBy epo:awa ;
    rdfs:subClassOf epo:Document ;
    skos:definition "A formal communication sent by the Buyer to inform Tenderers of the Award Decision."@en ;
    skos:historyNote "WG approval 11/09/2025"@en ;
    skos:prefLabel "Award Decision Notification"@en .

epo:concernsAwardOutcome a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:awa ;
    skos:definition "Relates to Award Outcome."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "concerns Award Outcome"@en .

epo:concernsProcedure a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:awa ;
    skos:definition "Relates to Procedure."@en ;
    skos:prefLabel "concerns Procedure"@en .

epo:hasStandstillPeriodEndDate a owl:DatatypeProperty ;
    rdfs:isDefinedBy epo:awa ;
    skos:definition "The end date for the mandatory minimum time frame between the communication of a contract award decision and the formal conclusion of the contract, during which unsuccessful Tenderers have the opportunity to challenge the award before it becomes legally binding. (epo-awa:AwardDecisionNotification)"@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "has Standstill Period End Date"@en .

epo:specifiesTenderer a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:awa ;
    skos:definition "Relation indicating that the instance of the concept involves the Tenderer."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "specifies Tenderer"@en .

epo:awa a owl:Ontology ;
    rdfs:label "eProcurement Ontology Awarding - core"@en ;
    dcterms:created "2021-06-01"^^xsd:date ;
    dcterms:description "The eProcurement Ontology Awarding core describes the concepts and properties representing the European Public Procurement Awarding domain. The provision of these semantics offers the basis for a common understanding of the domain for all stakeholders ensuring the quality of data exchange and transparency. The ontology restrictions are published in a separate artefact."@en ;
    dcterms:issued "2025-10-10"^^xsd:date ;
    dcterms:license "© European Union, 2014. Unless otherwise noted, the reuse of the Ontology is authorised under the European Union Public Licence v1.2 (https://eupl.eu/)." ;
    dcterms:publisher "http://publications.europa.eu/resource/authority/corporate-body/PUBL" ;
    dcterms:title "eProcurement Ontology Awarding - core"@en ;
    vann:preferredNamespacePrefix "epo" ;
    vann:preferredNamespaceUri "http://data.europa.eu/a4g/ontology#" ;
    rdfs:comment "This version is automatically generated from eAwarding.xml on 2025-10-10" ;
    rdfs:seeAlso <https://docs.ted.europa.eu/home/index.html>,
        <https://github.com/OP-TED/ePO/releases>,
        <https://joinup.ec.europa.eu/collection/eprocurement/solution/eprocurement-ontology/about>,
        <https://op.europa.eu/en/web/eu-vocabularies/e-procurement> ;
    owl:imports epo:core,
        <http://data.europa.eu/eli/ontology#>,
        <http://data.europa.eu/m8g/>,
        dcterms:,
        skos:,
        <http://www.w3.org/2006/time>,
        <http://www.w3.org/ns/adms>,
        <http://www.w3.org/ns/locn>,
        org:,
        <http://www.w3.org/ns/person> ;
    owl:incompatibleWith "4.2.0" ;
    owl:priorVersion "http://data.europa.eu/a4g/ontology#awa-5.1.0" ;
    owl:versionIRI epo:awa-5.2.0 ;
    owl:versionInfo "5.2.0" .



# ---- Source module: eCatalogue.ttl ----
@prefix dcterms: <http://purl.org/dc/terms/> .
@prefix epo: <http://data.europa.eu/a4g/ontology#> .
@prefix org: <http://www.w3.org/ns/org#> .
@prefix owl: <http://www.w3.org/2002/07/owl#> .
@prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .
@prefix skos: <http://www.w3.org/2004/02/skos/core#> .
@prefix vann: <http://purl.org/vocab/vann/> .
@prefix xsd: <http://www.w3.org/2001/XMLSchema#> .

epo:Batch a owl:Class ;
    rdfs:isDefinedBy epo:cat ;
    skos:definition "A production lot in which the Item instances were produced."@en ;
    skos:historyNote "WG Approval 10/03/2022"@en ;
    skos:prefLabel "Batch"@en .

epo:Brand a owl:Class ;
    rdfs:isDefinedBy epo:cat ;
    skos:definition "Name given by an organisation to its product or service, or range of products or services. Additional information: Brand name allows economic operators to distinctively describe an item in their eCatalogue. This may be different from the \"item name\"."@en ;
    skos:historyNote "WG Approval 10/03/2022"@en ;
    skos:prefLabel "Brand"@en .

epo:CatalogueLine a owl:Class ;
    rdfs:isDefinedBy epo:cat ;
    rdfs:subClassOf epo:Line ;
    skos:definition "Aggregated information about the Terms and specifications for procuring an Item. Details about an Item, like Prices, packaging, discounts, special promotions, etc. TC 440: Detailed information of an Item, Price and its composition in a Catalogue. Composition: e.g. information referring to its description, how to order it, what it is made of, properties, delivery conditions, etc."@en ;
    skos:prefLabel "Catalogue Line"@en .

epo:CatalogueResponse a owl:Class ;
    rdfs:isDefinedBy epo:cat ;
    skos:definition "A formal reply from the Catalogue Receiver to the Catalogue Provider stating the Catalogue Receiver's ability to apply the catalogue for placing orders. Additional Information: The Catalogue Response is used to inform on the acceptance or rejection of a Catalogue."@en ;
    skos:prefLabel "Catalogue Response"@en .

epo:CatalogueResponseInformation a owl:Class ;
    rdfs:isDefinedBy epo:cat ;
    skos:definition "Information about a Catalogue Response."@en ;
    skos:historyNote "WG approval 11/09/2025"@en ;
    skos:prefLabel "Catalogue Response Information"@en .

epo:CatalogueResponseLine a owl:Class ;
    rdfs:isDefinedBy epo:cat ;
    rdfs:subClassOf epo:Line ;
    skos:definition "Details concerning the Catalogue Receiver’s ability to apply a given Catalogue Line for placing orders. Additional information: The Catalogue Response Line is used to inform on the acceptance or rejection of a Catalogue Line."@en ;
    skos:prefLabel "Catalogue Response Line"@en .

epo:ChargeInformation a owl:Class ;
    rdfs:isDefinedBy epo:cat ;
    rdfs:subClassOf epo:AllowanceChargeInformation ;
    skos:definition "Information about fee or duty imposed. Additional Information: Charge category indicates the nature of the duty/fee, for example CAR, etc. Charge category modifier may be used in case different levels, exemptions or other modifications apply. The charge can be fixed or relative to the price."@en ;
    skos:historyNote "WG Approval 16/05/2023"@en ;
    skos:prefLabel "Charge Information"@en .

epo:DimensionInformation a owl:Class ;
    rdfs:isDefinedBy epo:cat ;
    skos:definition "Information about the physical or measurable attributes of the instance of the concept described."@en ;
    skos:historyNote "WG approval 11/09/2025"@en ;
    skos:prefLabel "Dimension Information"@en .

epo:EnvironmentalEmissionInformation a owl:Class ;
    rdfs:isDefinedBy epo:cat ;
    skos:definition "Information about the emissions related to a product, work or service that are released into the environment."@en ;
    skos:historyNote "WG approval 11/09/2025"@en ;
    skos:prefLabel "Environmental Emission Information"@en .

epo:InformationHub a owl:Class ;
    rdfs:isDefinedBy epo:cat ;
    rdfs:subClassOf epo:ContextDescription ;
    skos:definition "Grouping of data that may be associated to various concepts. Additional Information: For example, AllowanceChargeInformation may be associated to the Order or the Catalogue (either at the Line level or at the Document level), amongst others."@en ;
    skos:historyNote "WG Approval 16/05/2023"@en ;
    skos:prefLabel "Information Hub"@en .

epo:Item a owl:Class ;
    rdfs:isDefinedBy epo:cat ;
    rdfs:subClassOf epo:AbstractItem ;
    skos:definition "A product, work, service or any combination of them. Additional Information: An Item can be an atomic Thing or a composition of things that together are seen as a unit, e.g. a tetrabrik of milk or an indivisible package of six tetrabriks. No distinction is provided between services, goods and works to leave room for innovation. An Item is used to fulfill a need which is described in an Item Request."@en ;
    skos:historyNote "WG approval 09/10/2025"@en ;
    skos:prefLabel "Item"@en .

epo:ItemAccessoryRelation a owl:Class ;
    rdfs:isDefinedBy epo:cat ;
    rdfs:subClassOf epo:ItemRelation ;
    skos:definition "Combination of two Items where the former enhances the latter."@en ;
    skos:historyNote "WG Approval 30/06/2022"@en ;
    skos:prefLabel "Item Accessory Relation"@en .

epo:ItemComplementaryRelation a owl:Class ;
    rdfs:isDefinedBy epo:cat ;
    rdfs:subClassOf epo:ItemRelation ;
    skos:definition "Combination of two Items which mutually enhance one another."@en ;
    skos:historyNote "WG Approval 30/06/2022"@en ;
    skos:prefLabel "Item Complementary Relation"@en .

epo:ItemComposition a owl:Class ;
    rdfs:isDefinedBy epo:cat ;
    rdfs:subClassOf epo:ItemRelation ;
    skos:definition "Inclusion of an Item into in the described Item. Additional Information: The Item is provided with its components, however, the component Items may also be provided separately. For example, a bicycle has wheels as components, but they may be provided as spare parts as well. This relation is useful to describe different package levels of an item or hierarchies of Items."@en ;
    skos:historyNote "WG Approval 19/05/2022"@en ;
    skos:prefLabel "Item Composition"@en .

epo:ItemModel a owl:Class ;
    rdfs:isDefinedBy epo:cat ;
    skos:definition "A specific design or version of a product or service. Additional information: This class is meant as a reusable reference to the model name rather than as a set of specifications of an Item of this particular model."@en ;
    skos:historyNote "WG Approval 10/03/2022"@en ;
    skos:prefLabel "Item Model"@en .

epo:ItemProperty a owl:Class ;
    rdfs:isDefinedBy epo:cat ;
    skos:definition "Construct meant to represent the association between an attribute defined in an external classification scheme and the value ascribed to it."@en ;
    skos:historyNote "WG Approval 26/07/2022"@en ;
    skos:prefLabel "Item Property"@en .

epo:ItemReplacement a owl:Class ;
    rdfs:isDefinedBy epo:cat ;
    rdfs:subClassOf epo:ItemRelation ;
    skos:definition "Supplantment, displacement or suspension of an Item by the described Item."@en ;
    skos:historyNote "WG Approval 30/06/2022"@en ;
    skos:prefLabel "Item Replacement"@en .

epo:ItemRequirement a owl:Class ;
    rdfs:isDefinedBy epo:cat ;
    rdfs:subClassOf epo:ItemRelation ;
    skos:definition "Necessity of an Item by the described item. Additional Information: The described item is provided without other items that are required for proper functionality. For example, a printer cannot be used without ink cartridge; or a Server cannot be used without its installation."@en ;
    skos:historyNote "WG Approval 19/05/2022"@en ;
    skos:prefLabel "Item Requirement"@en .

epo:Manufacturer a owl:Class ;
    rdfs:isDefinedBy epo:cat ;
    rdfs:subClassOf epo:OfferingParty ;
    skos:definition "The Producer of goods or provider of services. Additional Information: Also, known as Supplier and Manufacturer. We do not care who provides these service or products we care with whom Business is done. PEPPOL - Invoice: The Supplier is the Legal Person or Organisation who provides a product and/or service. PEPPOL - Order: The supplier is the legal person or organisation who provides a product or service. Examples of supplier roles: seller, despatch party, creditor, economic operator."@en ;
    skos:prefLabel "Manufacturer"@en .

epo:PostAwardCatalogue a owl:Class ;
    rdfs:isDefinedBy epo:cat ;
    rdfs:subClassOf epo:Catalogue ;
    skos:definition "A Document describing a set of Items offered for purchase that can be processed in an electronic way, after a Contract is signed."@en ;
    skos:prefLabel "Post Award Catalogue"@en .

epo:PostAwardDocument a owl:Class ;
    rdfs:isDefinedBy epo:cat ;
    rdfs:subClassOf epo:Document ;
    skos:definition "Document created after the award of a Contract during a Procurement Procedure."@en ;
    skos:historyNote "WG approval 11/09/2025"@en ;
    skos:prefLabel "Post Award Document"@en .

epo:Price a owl:Class ;
    rdfs:isDefinedBy epo:cat ;
    skos:definition "Amount of money required or given in exchange for Items. Additional information: The Price excludes any charges (such as taxes, duties and fees) and discounts."@en ;
    skos:historyNote "WG approval 26/07/2022"@en ;
    skos:prefLabel "Price"@en .

epo:ProductSpecification a owl:Class ;
    rdfs:isDefinedBy epo:cat ;
    rdfs:subClassOf epo:Document ;
    skos:definition "Document providing information about an Item."@en ;
    skos:historyNote "WG Approval 07/04/2022"@en ;
    skos:prefLabel "Product Specification"@en .

epo:comprisesCatalogueLine a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:cat ;
    skos:definition "Incorporates Catalogue Line."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "comprises Catalogue Line"@en .

epo:comprisesCatalogueResponseLine a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:cat ;
    skos:definition "Incorporates Catalogue Response Line."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "comprises Catalogue Response Line"@en .

epo:concernsGoodsItem a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:cat ;
    skos:definition "Relates to Goods Item."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "concerns Goods Item"@en .

epo:concernsItem a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:cat ;
    skos:definition "Relates to Item."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "concerns Item"@en .

epo:concernsPackage a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:cat ;
    skos:definition "Relates to Package."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "concerns Package"@en .

epo:concernsTransportEquipment a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:cat ;
    skos:definition "Relates to Transport Equipment."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "concerns Transport Equipment"@en .

epo:concernsTransportMeans a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:cat ;
    skos:definition "Relates to Transport Means."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "concerns Transport Means"@en .

epo:describesItem a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:cat ;
    skos:definition "Characterises Item."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "describes Item"@en .

epo:foreseesPackage a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:cat ;
    skos:definition "Relation indicating that an instance of the concept plans to have a Package."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "foresees Package"@en .

epo:hasAccessoryItem a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:cat ;
    skos:definition "An additional item that can enhance the original item."@en ;
    skos:historyNote "WG Approval 30/06/2022"@en ;
    skos:prefLabel "has Accessory Item"@en .

epo:hasActivityCode a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:cat ;
    skos:definition "Relation indicating the Activity Code."@en ;
    skos:prefLabel "has Activity Code"@en .

epo:hasAdditionalInformation a owl:DatatypeProperty ;
    rdfs:isDefinedBy epo:cat ;
    skos:definition "Supplementary data about the instance of the concept. (epo-cat:Line)"@en ;
    skos:historyNote "WG Approval 15/10/2019"@en ;
    skos:prefLabel "has Additional Information"@en .

epo:hasAssociatedDocument a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:cat ;
    skos:definition "Is related to a Document."@en ;
    skos:historyNote "WG Approval 06/10/2024"@en ;
    skos:prefLabel "has Associated Document"@en .

epo:hasAttributeType a owl:DatatypeProperty ;
    rdfs:isDefinedBy epo:cat ;
    skos:definition "The property defined in a classification scheme. Additional Information: For example, the following two properties are defined in the ECLASS classification of goods and services: (0173-1#02-AAA026#007) drilling diameter: drilling diameter, (0173-1#02-AAA030#007) flange diameter: flange diameter . (epo-cat:ItemProperty)"@en ;
    skos:historyNote "WG Approval 28/07/2022"@en ;
    skos:prefLabel "has Attribute Type"@en .

epo:hasBaseQuantity a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:cat ;
    skos:definition "The quantity at which the net monetary value applies."@en ;
    skos:prefLabel "has Base Quantity"@en .

epo:hasBatchID a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:cat ;
    skos:definition "The identifier assigned to a specific batch of the produced Item."@en ;
    skos:historyNote "WG Approval 16/05/2023"@en ;
    skos:prefLabel "has Batch ID"@en .

epo:hasBestBeforeDate a owl:DatatypeProperty ;
    rdfs:isDefinedBy epo:cat ;
    skos:definition "The day until which the quality of the item will remain optimal. (epo-cat:Batch)"@en ;
    skos:historyNote "WG Approval 10/03/2021"@en ;
    skos:prefLabel "has Best Before Date"@en .

epo:hasBrand a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:cat ;
    skos:definition "Relation indicating that the instance of the concept has a Brand."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "has Brand"@en .

epo:hasBuyerItemID a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:cat ;
    skos:definition "The general identifier assigned to the concept as defined by the Buyer.​"@en ;
    skos:historyNote "WG Approval 16/05/2023"@en ;
    skos:prefLabel "has Buyer Item ID"@en .

epo:hasCalculationMethod a owl:DatatypeProperty ;
    rdfs:isDefinedBy epo:cat ;
    skos:definition "Formula for obtaining values. Additional Information: The possible values are monetary values, ranking scores, criterion weighting. (epo-cat:EnvironmentalEmissionInformation)"@en ;
    skos:historyNote "WG Approval 25/05/2018"@en ;
    skos:prefLabel "has Calculation Method"@en .

epo:hasCatalogueLineValidity a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:cat ;
    skos:definition "The relation indicating until when a Catalogue Line instance is applicable."@en ;
    skos:historyNote "WG Approval 21/09/2023"@en ;
    skos:prefLabel "has Catalogue Line Validity"@en .

epo:hasCertification a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:cat ;
    skos:definition "Relation to the proof of conformance."@en ;
    skos:historyNote "WG Approval 30/05/2023"@en ;
    skos:prefLabel "has Certification"@en .

epo:hasChargeInformation a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:cat ;
    skos:definition "Relation indicating that the instance of the concept has Charge Information."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
