epo:announcesContractAmendment a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:con ;
    skos:definition "Relation indicating the formal communication of a Contract Amendment."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "announces Contract Amendment"@en .

epo:concernsContractAmendment a owl:ObjectProperty ;
