    skos:editorialNote "Used by eForms BT-201, TEDXML F20 VII.2.2.2, TEDXML F20 VII.2.2.4"@en ;
    skos:historyNote "WG Approval 05/11/2019"@en ;
    skos:prefLabel "has Modification Reason Description"@en .

epo:hasQuantity a owl:ObjectProperty ;
