@prefix skos: <http://www.w3.org/2004/02/skos/core#> .
@prefix vann: <http://purl.org/vocab/vann/> .
@prefix xsd: <http://www.w3.org/2001/XMLSchema#> .

epo:EvaluationBoard a owl:Class ;
    rdfs:isDefinedBy epo:eva ;
    skos:definition "Committee set up to evaluate the Tenders submitted. Additional Information: The committee may be a regular board or a jury."@en ;
    skos:historyNote "WG approval 13/04/2021"@en ;
    skos:prefLabel "Evaluation Board"@en .

epo:EvaluationCriterion a owl:Class ;
    rdfs:isDefinedBy epo:eva ;
    skos:definition "A Criterion used by the Buyer to assess and compare Tenders in order to determine which Offer best meets the objectives of the Procurement Procedure."@en ;
    skos:historyNote "WG approval 11/09/2025"@en ;
    skos:prefLabel "Evaluation Criterion"@en .

epo:EvaluationReport a owl:Class ;
    rdfs:isDefinedBy epo:eva ;
    rdfs:subClassOf epo:Document ;
    skos:definition "Summary of the Evaluation."@en ;
    skos:historyNote "WG approval 16/09/2025"@en ;
    skos:prefLabel "Evaluation Report"@en .

epo:Evaluator a owl:Class ;
    rdfs:isDefinedBy epo:eva ;
    rdfs:subClassOf epo:AcquiringParty ;
    skos:definition "A Role of an Agent that asses the Tender submitted for a Lot."@en ;
    skos:historyNote "WG approval 16/09/2025"@en ;
    skos:prefLabel "Evaluator"@en .

epo:ExcludedCandidateList a owl:Class ;
    rdfs:isDefinedBy epo:eva ;
    skos:definition "Record of Candidates prevented from participating in a Procurement because one or more Exclusion Grounds apply."@en ;
    skos:historyNote "WG approval 16/09/2025"@en ;
    skos:prefLabel "Excluded Candidate List"@en .

epo:TenderClarification a owl:Class ;
    rdfs:isDefinedBy epo:eva ;
    rdfs:subClassOf epo:ProcurementDocument ;
    skos:definition "A Document sent by the Tenderer to the Buyer in response to the Tender Clarification Request. Additional Information: The Tender Clarification may not alter the Tender."@en ;
    skos:historyNote "WG approval 16/09/2025"@en ;
    skos:prefLabel "Tender Clarification"@en .

epo:TenderClarificationRequest a owl:Class ;
    rdfs:isDefinedBy epo:eva ;
    rdfs:subClassOf epo:Document ;
    skos:definition "A demand for elucidation of specific aspects of the Tender. Additional Information: This request and its answer may not alter the Tender."@en ;
    skos:prefLabel "Tender Clarification Request"@en .

epo:concernsEvaluationReport a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:eva ;
    skos:definition "Relates to Evaluation Report."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "concerns Evaluation Report"@en .

epo:containsCandidate a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:eva ;
    skos:prefLabel "contains Candidate"@en .

epo:evaluatesProcurementCriterion a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:eva ;
    skos:definition "Assesses Procurement Criterion."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "evaluates Procurement Criterion"@en .

epo:fulfillsProcurementCriterion a owl:DatatypeProperty ;
    rdfs:isDefinedBy epo:eva ;
    skos:definition "Indicates whether the Procurement Criterion is satisfied. (epo-eva:EvaluationCriterion)"@en ;
    skos:historyNote "WG approval 25/09/2026"@en ;
    skos:prefLabel "fulfills Procurement Criterion"@en .

epo:hasAwardCriteriaEvaluationScore a owl:DatatypeProperty ;
    rdfs:isDefinedBy epo:eva ;
    skos:definition "The total number of points obtained while assessing the Award Criteria. (epo-eva:EvaluationReport)"@en ;
    skos:historyNote "WG approval 25/09/2026"@en ;
    skos:prefLabel "has Award Criteria Evaluation Score"@en .

epo:hasEvaluationJustification a owl:DatatypeProperty ;
    rdfs:isDefinedBy epo:eva ;
    skos:definition "The motivation behind the Evaluation result. (epo-eva:EvaluationCriterion)"@en ;
    skos:historyNote "WG approval 25/09/2026"@en ;
    skos:prefLabel "has Evaluation Justification"@en .

epo:hasEvaluator a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:eva ;
    skos:definition "Relation indicating that the instance of the concept has an Evaluator."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "has Evaluator"@en .

epo:hasJuryMember a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:eva ;
    skos:definition "An agent involved in an evaluation board."@en ;
    skos:historyNote "WG Approval 14/09/2021"@en ;
    skos:prefLabel "has Jury Member"@en .

epo:hasScorePoint a owl:DatatypeProperty ;
    rdfs:isDefinedBy epo:eva ;
    skos:definition "The grade value assigned to a Procurement Criterion. (epo-eva:EvaluationCriterion)"@en ;
    skos:historyNote "WG approval 25/09/2026"@en ;
    skos:prefLabel "has Score Point"@en .

epo:isAppointedBy a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:eva ;
    skos:definition "Relation indicating that by whom the instance of the concept is formally assigned."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "is Appointed By"@en .

epo:isAssignedForEvaluationOf a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:eva ;
    skos:definition "Relation indicating that the instance of the concept is selected for Evaluation."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "is Assigned For Evaluation Of"@en .

epo:playedBy a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:eva ;
    skos:definition "Relation indicating the Agent that fulfills the function of the instance of the concept."@en ;
    skos:historyNote "WG approval 09/10/2025"@en ;
    skos:prefLabel "played By"@en .

epo:providesRankToTender a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:eva ;
    skos:definition "Makes available the assigned position for the Tender."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "provides Rank To Tender"@en .

epo:refersToTenderClarificationRequest a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:eva ;
    skos:definition "Reference to a Tender Clarification Request."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "refers To Tender Clarification Request"@en .

epo:reportsEvaluationCriterion a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:eva ;
    skos:definition "Provides an Evaluation Criterion."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "reports Evaluation Criterion"@en .

epo:requestsClarification a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:eva ;
    skos:definition "Asks for more information."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "requests Clarification"@en .

epo:specifiesEconomicOperator a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:eva ;
    skos:definition "Relation indicating that the instance of the concept involves the Economic Operator."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "specifies Economic Operator"@en .

epo:usesEvaluationFormula a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:eva ;
    skos:definition "Applies systematic method for assessment."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "uses Evaluation Formula"@en .

epo:writesEvaluationReport a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:eva ;
    skos:definition "Authors an Evaluation Report."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "writes Evaluation Report"@en .

epo:eva a owl:Ontology ;
