# ---- Source module: eFulfilment.ttl ----
@prefix dcterms: <http://purl.org/dc/terms/> .
@prefix epo: <http://data.europa.eu/a4g/ontology#> .
@prefix org: <http://www.w3.org/ns/org#> .
@prefix owl: <http://www.w3.org/2002/07/owl#> .
@prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .
@prefix skos: <http://www.w3.org/2004/02/skos/core#> .
@prefix vann: <http://purl.org/vocab/vann/> .
@prefix xsd: <http://www.w3.org/2001/XMLSchema#> .

epo:Carrier a owl:Class ;
    rdfs:isDefinedBy epo:ful ;
    rdfs:subClassOf epo:AuxiliaryParty ;
    skos:definition "The Role of an Agent who handles the physical Delivery/Transportation of the (Despatched) Shipment. Additional Information: This Role is often referred to as the deliverer."@en ;
    skos:historyNote "WG Approval 14/05/2024"@en ;
    skos:prefLabel "Carrier"@en .

epo:Consignment a owl:Class ;
    rdfs:isDefinedBy epo:ful ;
    skos:definition "A batch of goods destined for or delivered to someone. Additional information: Consignment is a Transport Agreement between the Despatcher and the Consignee as to who and how the goods are despatched and received."@en ;
    skos:historyNote "WG Approval 14/05/2024"@en ;
    skos:prefLabel "Consignment"@en .

epo:DespatchAdvice a owl:Class ;
    rdfs:isDefinedBy epo:ful ;
    rdfs:subClassOf epo:PostAwardDocument ;
    skos:definition "A document notifying the sending of goods or the execution of works or services."@en ;
    skos:historyNote "WG Approval 14/05/2024"@en ;
    skos:prefLabel "Despatch Advice"@en .

epo:DespatchLine a owl:Class ;
    rdfs:isDefinedBy epo:ful ;
    rdfs:subClassOf epo:Line ;
    skos:definition "Details concerning the fulfilment of an Order Line."@en ;
    skos:historyNote "WG Approval 21/05/2024"@en ;
    skos:prefLabel "Despatch Line"@en .

epo:Despatcher a owl:Class ;
    rdfs:isDefinedBy epo:ful ;
    rdfs:subClassOf epo:OfferingParty ;
    skos:definition "The Role of an Agent who sends the goods or notifies of the service or works execution. Additional Information: The Role is carried out by the Supplier or on behalf of the Supplier. This Role is often referred to as the Despatch Party, Consignor or Deliverer."@en ;
    skos:historyNote "WG Approval 02/07/2024"@en ;
    skos:prefLabel "Despatcher"@en .

epo:FreightForwarder a owl:Class ;
    rdfs:isDefinedBy epo:ful ;
    rdfs:subClassOf epo:AuxiliaryParty ;
    skos:definition "The Role of an Agent who organise the logistic operations need for a fulfilment."@en ;
    skos:historyNote "WG Approval 21/05/2024"@en ;
    skos:prefLabel "Freight Forwarder"@en .

epo:GoodsItem a owl:Class ;
    rdfs:isDefinedBy epo:ful ;
    skos:definition "An Item including its initial packaging during transportation. Additional information: For example, the Item being bought is the computer. The weight of the computer is X. The weight of the Goods Item is the weight of the computer plus the weight of the initial packaging. During transportation you have for example trace ID which is applied to the GoodsItem, rather than on the Item itself. The declared statistical value can only apply once you have a GoodsItem."@en ;
    skos:historyNote "WG Approval 30/03/2023"@en ;
    skos:prefLabel "Goods Item"@en .

epo:NotificationReceiver a owl:Class ;
    rdfs:isDefinedBy epo:ful ;
    rdfs:subClassOf epo:AuxiliaryParty ;
    skos:definition "The Role of an Agent that is informed about the arrival of a Shipment at a destination. Additional information: This could be for example customs and excise."@en ;
    skos:historyNote "WG Approval 21/05/2024"@en ;
    skos:prefLabel "Notification Receiver"@en .

epo:ReceiptAdvice a owl:Class ;
    rdfs:isDefinedBy epo:ful ;
    rdfs:subClassOf epo:PostAwardDocument ;
    skos:definition "A formal reply from the Buyer to the Seller acknowledging the physical or electronic receipt of goods or services delivered under a Procurement Contract."@en ;
    skos:historyNote "WG approval 16/09/2025"@en ;
    skos:prefLabel "Receipt Advice"@en .

epo:ReceiptAdviceInformation a owl:Class ;
    rdfs:isDefinedBy epo:ful ;
    rdfs:subClassOf epo:InformationHub ;
    skos:definition "Information about the Receipt Advice."@en ;
    skos:historyNote "WG approval 16/09/2025"@en ;
    skos:prefLabel "Receipt Advice Information"@en .

epo:ReceiptAdviceLine a owl:Class ;
    rdfs:isDefinedBy epo:ful ;
    rdfs:subClassOf epo:Line ;
    skos:definition "Details concerning the Fulfilment of a Despatch Line."@en ;
    skos:historyNote "WG approval 16/09/2025"@en ;
    skos:prefLabel "Receipt Advice Line"@en .

epo:ShipmentAgreement a owl:Class ;
    rdfs:isDefinedBy epo:ful ;
    skos:definition "The commercial agreement between the Buyer and the Seller. Additional Information: The Shipment Agreement describes the items being shipped."@en ;
    skos:historyNote "WG Approval 21/05/2024"@en ;
    skos:prefLabel "Shipment Agreement"@en .

epo:ShipmentInformation a owl:Class ;
    rdfs:isDefinedBy epo:ful ;
