    rdfs:isDefinedBy epo:inv ;
    skos:definition "A unique identifier of the financial payment account, at a payment service provider, to which payment should be made."@en ;
    skos:historyNote "WG Approval 11/07/2024"@en ;
    skos:prefLabel "has Payment Account Identifier"@en .

