    skos:historyNote "WG Approval 02/05/2024"@en ;
    skos:prefLabel "Pre Market Consultation Notice"@en .

epo:concernsProcedure a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:not ;
    skos:definition "Relates to Procedure."@en ;
    skos:prefLabel "concerns Procedure"@en .

epo:SubcontractNotice a owl:Class ;
    rdfs:isDefinedBy epo:not ;
    rdfs:subClassOf epo:CompetitionNotice ;
    skos:definition "Announcement of a call for competition by successful tenderers which are not contracting authorities/entities concerning contracts for social and other specific services."@en ;
    skos:historyNote "WG approval 09/10/2025"@en ;
    skos:prefLabel "Subcontract Notice"@en .

epo:PIN-CFCStandardNotice a owl:Class ;
    rdfs:isDefinedBy epo:not ;
    rdfs:subClassOf epo:CompetitionNotice ;
    skos:definition "Announcement of intentions of planned procurements used as a call for competition. Additional information: For restricted procedures and competitive procedures with negotiation, sub-central contracting authorities may use a prior information notice as a call for competition pursuant to the relevant article of the Directive."@en ;
    skos:historyNote "WG approval 09/10/2025"@en ;
    skos:prefLabel "PI N- CFC Standard Notice"@en .

epo:QSNotice a owl:Class ;
    rdfs:isDefinedBy epo:not ;
    rdfs:subClassOf epo:CompetitionNotice ;
    skos:definition "Announcement of a system of qualification of economic operators on the basis of exclusion and selection criteria. Additional information: The announcement can be used as a call for competition. When a call for competition is made by means of a notice on the existence of a qualification system, specific contracts for the works, supplies or services covered by the qualification system shall be awarded by restricted procedures or negotiated procedures, in which all tenderers and participants are selected among the candidates already qualified in accordance with such a system."@en ;
    skos:historyNote "WG approval 09/10/2025"@en ;
    skos:prefLabel "QS Notice"@en .

epo:CNSocialNotice a owl:Class ;
    rdfs:isDefinedBy epo:not ;
    rdfs:subClassOf epo:CompetitionNotice ;
    skos:definition "Announcement of a call for competition concerning contracts for social and other specific services."@en ;
    skos:historyNote "WG approval 09/10/2025"@en ;
    skos:prefLabel "CN Social Notice"@en .

epo:DesignContestNotice a owl:Class ;
    rdfs:isDefinedBy epo:not ;
    rdfs:subClassOf epo:CompetitionNotice ;
    skos:definition "Announcement of a call for competition concerning the acquisition, mainly in the fields of town and country planning, architecture and engineering or data processing, of a plan or design selected by a jury."@en ;
    skos:historyNote "WG approval 09/10/2025"@en ;
    skos:prefLabel "Design Contest Notice"@en .

epo:DesignContestResultNotice a owl:Class ;
    rdfs:isDefinedBy epo:not ;
    rdfs:subClassOf epo:ResultNotice ;
    skos:definition "Announcement of the results of a call for competition concerning the acquisition, mainly in the fields of town and country planning, architecture and engineering or data processing, of a plan or design selected by a jury."@en ;
    skos:historyNote "WG approval 09/10/2025"@en ;
    skos:prefLabel "Design Contest Result Notice"@en .

epo:CANSocialNotice a owl:Class ;
    rdfs:isDefinedBy epo:not ;
    rdfs:subClassOf epo:ResultNotice ;
    skos:definition "Announcement of the results of a call for competition concerning contracts or concessions for social and other specific services."@en ;
    skos:historyNote "WG approval 09/10/2025"@en ;
    skos:prefLabel "CAN Social Notice"@en .

epo:PIN-CFCSocialNotice a owl:Class ;
    rdfs:isDefinedBy epo:not ;
    rdfs:subClassOf epo:CompetitionNotice ;
    skos:definition "Announcement of intentions of planned procurements used as a call for competition concerning contracts for social and other specific services."@en ;
    skos:historyNote "WG approval 09/10/2025"@en ;
    skos:prefLabel "PI N- CFC Social Notice"@en .

epo:PINTimeLimitNotice a owl:Class ;
    rdfs:isDefinedBy epo:not ;
    rdfs:subClassOf epo:PlanningNotice ;
    skos:definition "Announcement of intentions of planned procurements in view of shortening time limits for reception of tenders. Additional information: Where contracting authorities have published a prior information notice which was not itself used as a means of calling for competition, the minimum time limit for the receipt of tenders may be shortened."@en ;
    skos:historyNote "WG approval 09/10/2025"@en ;
    skos:prefLabel "PIN Time Limit Notice"@en .

epo:PlanningNotice a owl:Class ;
    rdfs:isDefinedBy epo:not ;
    rdfs:subClassOf epo:Notice ;
    skos:definition "Notice which sets out the Contracting Authority's purchasing intentions. It is used by Contracting Authorities to provide Suppliers with information about a Procurement Process."@en ;
    skos:prefLabel "Planning Notice"@en .

epo:ResultNotice a owl:Class ;
    rdfs:isDefinedBy epo:not ;
    rdfs:subClassOf epo:Notice ;
    skos:definition "An announcement of the award or non-award of a Contract by a Buyer."@en ;
    skos:historyNote "WG Approval 27/03/2019"@en ;
    skos:prefLabel "Result Notice"@en .

epo:CANStandardNotice a owl:Class ;
    rdfs:isDefinedBy epo:not ;
    rdfs:subClassOf epo:ResultNotice ;
    skos:definition "Announcement of the results of a call for competition concerning contracts or concessions."@en ;
    skos:historyNote "WG approval 09/10/2025"@en ;
    skos:prefLabel "CAN Standard Notice"@en .

epo:CNStandardNotice a owl:Class ;
    rdfs:isDefinedBy epo:not ;
    rdfs:subClassOf epo:CompetitionNotice ;
    skos:definition "Announcement of a call for competition concerning contracts or concessions. Additional information: Contract notices shall be used as a means of calling for competition in respect of all procedures, without prejudice to the relevant articles of the Directive."@en ;
    skos:historyNote "WG approval 09/10/2025"@en ;
    skos:prefLabel "CN Standard Notice"@en .

epo:PINOnlyNotice a owl:Class ;
    rdfs:isDefinedBy epo:not ;
    rdfs:subClassOf epo:PlanningNotice ;
    skos:definition "Announcement of intentions of planned procurements for information purposes."@en ;
    skos:historyNote "WG approval 09/10/2025"@en ;
    skos:prefLabel "PIN Only Notice"@en .

epo:PINProfileNotice a owl:Class ;
    rdfs:isDefinedBy epo:not ;
    rdfs:subClassOf epo:PlanningNotice ;
    skos:definition "Announcement of intentions of planned procurements."@en ;
    skos:historyNote "WG approval 09/10/2025"@en ;
    skos:prefLabel "PIN Profile Notice"@en .

epo:ContractModificationNotice a owl:Class ;
    rdfs:isDefinedBy epo:not ;
    rdfs:subClassOf epo:Notice ;
    skos:definition "An announcement of the Modification of a Contract/Concession during its term by a Procuring Entity."@en ;
    skos:prefLabel "Contract Modification Notice"@en .

epo:CompetitionNotice a owl:Class ;
    rdfs:isDefinedBy epo:not ;
    rdfs:subClassOf epo:Notice ;
    skos:definition "An announcement of the launch of a Procurement Procedure by a Procuring Entity."@en ;
    skos:historyNote "WG Approval 18/05/2018"@en ;
    skos:prefLabel "Competition Notice"@en .

epo:VoluntaryEx-AnteTransparencyNotice a owl:Class ;
    rdfs:isDefinedBy epo:not ;
    rdfs:subClassOf epo:DirectAwardPrenotificationNotice ;
    skos:definition "Announcement of the intention to award of a contract without prior publication of a contract notice."@en ;
    skos:historyNote "WG approval 09/10/2025"@en ;
    skos:prefLabel "Voluntary Ex- Ante Transparency Notice"@en .

epo:StandardFormsNotice a owl:Class ;
    rdfs:isDefinedBy epo:not ;
    skos:definition "Standard Forms Notice"@en ;
    skos:prefLabel "Standard Forms Notice"@en .

epo:eFormsNotice a owl:Class ;
    rdfs:isDefinedBy epo:not ;
    skos:definition "eForms Notice"@en ;
    skos:prefLabel "e Forms Notice"@en .

