# ---- Source module: eOrdering.ttl ----
@prefix dcterms: <http://purl.org/dc/terms/> .
@prefix epo: <http://data.europa.eu/a4g/ontology#> .
@prefix org: <http://www.w3.org/ns/org#> .
@prefix owl: <http://www.w3.org/2002/07/owl#> .
@prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .
@prefix skos: <http://www.w3.org/2004/02/skos/core#> .
@prefix vann: <http://purl.org/vocab/vann/> .
@prefix xsd: <http://www.w3.org/2001/XMLSchema#> .

epo:AllowanceInformation a owl:Class ;
    rdfs:isDefinedBy epo:ord ;
    rdfs:subClassOf epo:AllowanceChargeInformation ;
    skos:definition "Information about the discounts imposed."@en ;
    skos:historyNote "WG Approval 16/05/2023"@en ;
    skos:prefLabel "Allowance Information"@en .

epo:Consignee a owl:Class ;
    rdfs:isDefinedBy epo:ord ;
    rdfs:subClassOf epo:AcquiringParty ;
    skos:definition "A Role of an Agent that receives the Shipment of the Procurement (service, goods or works) and who is taking possession. Additional information: The Role is carried out by the Customer or on behalf of the Customer. The possession of the goods does not necessary imply ownership. The Consignee may be the end-user or the beneficiary. (Consignee) Definition from PEPPOL Despatch: The Consignee is the person or Organisation to which the products will be shipped and who is taking possession. The Role is carried out by the Customer or on behalf of the Customer."@en ;
    skos:historyNote "WG Approval 21/02/2023"@en ;
    skos:prefLabel "Consignee"@en .

epo:ContractInformation a owl:Class ;
    rdfs:isDefinedBy epo:ord ;
    rdfs:subClassOf epo:InformationHub ;
    skos:definition "Information about the Contract."@en ;
    skos:historyNote "WG Approval 20/04/2023"@en ;
    skos:prefLabel "Contract Information"@en .

epo:DeliveryAgreement a owl:Class ;
    rdfs:isDefinedBy epo:ord ;
    skos:definition "Term applying to the delivery of goods, services and works. Additional Information: Delivery terms identifier can normally be Incoterms accompanied by the description of specific conditions related to the delivery."@en ;
    skos:historyNote "WG Approval 16/05/2023"@en ;
    skos:prefLabel "Delivery Agreement"@en .

epo:DeliveryInformation a owl:Class ;
    rdfs:isDefinedBy epo:ord ;
    rdfs:subClassOf epo:InformationHub ;
    skos:definition "Information about the timing, the delivery destination, the delivery agreement and the involved parties."@en ;
    skos:historyNote "WG Approval 16/05/2023"@en ;
    skos:prefLabel "Delivery Information"@en .

epo:Invoicee a owl:Class ;
    rdfs:isDefinedBy epo:ord ;
    rdfs:subClassOf epo:AcquiringParty ;
    skos:definition "The Role of an Agent who receives and processes the Invoices."@en ;
    skos:historyNote "WG Approval 03/04/2025"@en ;
    skos:prefLabel "Invoicee"@en .

epo:OrderAgreement a owl:Class ;
    rdfs:isDefinedBy epo:ord ;
    rdfs:subClassOf epo:Order ;
    skos:definition "A Document sent from the Seller to Buyer specifying the goods, services or works to be delivered concerning a specific Order."@en ;
    skos:historyNote "WG approval 16/09/2025"@en ;
    skos:prefLabel "Order Agreement"@en .

epo:OrderAgreementLine a owl:Class ;
    rdfs:isDefinedBy epo:ord ;
    rdfs:subClassOf epo:OrderLine ;
    skos:definition "Details concerning a given unit of goods, services or works mentioned in the Order Agreement."@en ;
    skos:historyNote "WG approval 16/09/2025"@en ;
    skos:prefLabel "Order Agreement Line"@en .

epo:OrderCancellation a owl:Class ;
    rdfs:isDefinedBy epo:ord ;
    rdfs:subClassOf epo:PostAwardDocument ;
    skos:definition "A Document providing information on the formal response from the Buyer to the Seller to cancel a previous Order or Order Change."@en ;
    skos:historyNote "WG approval 16/09/2025"@en ;
    skos:prefLabel "Order Cancellation"@en .

epo:OrderCancellationConfirmation a owl:Class ;
    rdfs:isDefinedBy epo:ord ;
    rdfs:subClassOf epo:PostAwardDocument ;
    skos:definition "A Document providing information on the acknowledgment of the Order Cancellation."@en ;
    skos:historyNote "WG approval 16/09/2025"@en ;
    skos:prefLabel "Order Cancellation Confirmation"@en .

epo:OrderCancellationRejection a owl:Class ;
    rdfs:isDefinedBy epo:ord ;
    rdfs:subClassOf epo:PostAwardDocument ;
    skos:definition "A Document providing information on the non-acceptance of the Order Cancellation."@en ;
    skos:historyNote "WG approval 16/09/2025"@en ;
    skos:prefLabel "Order Cancellation Rejection"@en .

epo:OrderChange a owl:Class ;
    rdfs:isDefinedBy epo:ord ;
    rdfs:subClassOf epo:Order ;
    skos:definition "A Document providing information on the formal request from the Buyer to the Seller specifying the requested change in goods, services or works to be delivered in respect to a previous Order."@en ;
    skos:historyNote "WG approval 16/09/2025"@en ;
    skos:prefLabel "Order Change"@en .

epo:OrderChangeConfirmation a owl:Class ;
    rdfs:isDefinedBy epo:ord ;
    rdfs:subClassOf epo:PostAwardDocument ;
    skos:definition "A Document providing information on the acknowledgment of the Order Change."@en ;
    skos:historyNote "WG approval 16/09/2025"@en ;
    skos:prefLabel "Order Change Confirmation"@en .

epo:OrderChangeLine a owl:Class ;
    rdfs:isDefinedBy epo:ord ;
    rdfs:subClassOf epo:OrderLine ;
    skos:definition "Details concerning a given unit of goods, services or works requested in the Order Change."@en ;
    skos:historyNote "WG approval 16/09/2025"@en ;
    skos:prefLabel "Order Change Line"@en .

epo:OrderChangeRejection a owl:Class ;
    rdfs:isDefinedBy epo:ord ;
    rdfs:subClassOf epo:PostAwardDocument ;
    skos:definition "A Document providing information on the non-acceptance of the Order Change."@en ;
    skos:historyNote "WG approval 16/09/2025"@en ;
    skos:prefLabel "Order Change Rejection"@en .

epo:OrderResponse a owl:Class ;
    rdfs:isDefinedBy epo:ord ;
    rdfs:subClassOf epo:Order ;
    skos:definition "A formal reply from the Seller to the Buyer stating the Seller's ability to fulfil the order. Additional Information: The Order Response is used to inform on the acceptance or rejection of an Order or to make a counter-offer."@en ;
    skos:historyNote "WG Approval 20/04/2023"@en ;
    skos:prefLabel "Order Response"@en .

epo:OrderResponseInformation a owl:Class ;
    rdfs:isDefinedBy epo:ord ;
    rdfs:subClassOf epo:InformationHub ;
    skos:definition "Information about an Order Response."@en ;
    skos:historyNote "WG approval 16/09/2025"@en ;
    skos:prefLabel "Order Response Information"@en .

epo:OrderResponseLine a owl:Class ;
    rdfs:isDefinedBy epo:ord ;
    rdfs:subClassOf epo:OrderLine ;
    skos:definition "Details concerning the Seller's ability to fulfil a given Order Line. Additional Information: The Order Response Line is used to inform on the acceptance or rejection of an Order Line or to make a counter-offer."@en ;
    skos:historyNote "WG Approval 20/04/2023"@en ;
    skos:prefLabel "Order Response Line"@en .

epo:Originator a owl:Class ;
    rdfs:isDefinedBy epo:ord ;
    rdfs:subClassOf epo:AcquiringParty ;
    skos:definition "A Role of an Agent that expresses the needs to trigger the Procurement. Additional Information: The Originator is often the end-user or the Beneficiary."@en ;
    skos:historyNote "WG Approval 20/10/2022"@en ;
    skos:prefLabel "Originator"@en .

epo:OriginatorInformation a owl:Class ;
    rdfs:isDefinedBy epo:ord ;
    rdfs:subClassOf epo:InformationHub ;
    skos:definition "Information about the Originator of the Order."@en ;
    skos:historyNote "WG Approval 20/03/2023"@en ;
    skos:prefLabel "Originator Information"@en .

epo:Seller a owl:Class ;
    rdfs:isDefinedBy epo:ord ;
    rdfs:subClassOf epo:OfferingParty ;
    skos:definition "A Role of an Agent who transfers the ownership of the Procurement results (goods, services or works) to the Buyer. Additional information: A Role of an Agent that sells a Procurement Result (goods, services or work) to a Buyer. The Seller is bound by a Contract i.e. it has legal responsibility. The Seller may or may not be the same as the Supplier. The Seller may or may not issue the Invoice. The Seller may or may not be the owner of the credit owed by the Buyer."@en ;
    skos:historyNote "WG Approval 08/09/2022"@en ;
    skos:prefLabel "Seller"@en .

epo:TaxInformation a owl:Class ;
    rdfs:isDefinedBy epo:ord ;
    rdfs:subClassOf epo:InformationHub ;
    skos:definition "Information about the imposition of mandatory levies required by law."@en ;
    skos:historyNote "WG Approval 25/04/2023"@en ;
    skos:prefLabel "Tax Information"@en .

epo:agreedBySeller a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:ord ;
    skos:definition "Accepted by Seller."@en ;
    skos:historyNote "WG Approval 10/06/2024"@en ;
    skos:prefLabel "agreed By Seller"@en .

epo:comprisesOrderAgreementLine a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:ord ;
    skos:definition "Incorporates Order Agreement Line."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "comprises Order Agreement Line"@en .

epo:comprisesOrderChangeLine a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:ord ;
    skos:definition "Incorporates Order Change Line."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "comprises Order Change Line"@en .

epo:comprisesOrderLine a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:ord ;
    skos:definition "Incorporates Order Line."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "comprises Order Line"@en .

epo:comprisesOrderResponseLine a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:ord ;
    skos:definition "Incorporates Order Response Line."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "comprises Order Response Line"@en .

epo:concernsConsignee a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:ord ;
    skos:definition "Relates to Consignee."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "concerns Consignee"@en .

epo:concernsContract a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:ord ;
    skos:definition "Relates to Contractor."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "concerns Contract"@en .

epo:concernsOriginator a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:ord ;
    skos:definition "Relates to Originator."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "concerns Originator"@en .

epo:concernsOriginatorRequest a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:ord ;
    skos:definition "Relates to Originator Request."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "concerns Originator Request"@en .

epo:hasAcceptanceStatus a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:ord ;
    skos:definition "Relation indicating the acceptance status."@en ;
    skos:prefLabel "has Acceptance Status"@en .

epo:hasAccessURL a owl:DatatypeProperty ;
    rdfs:isDefinedBy epo:ord ;
    skos:definition "Location where the resource can be accessed. (epo-ord:DeliveryInformation)"@en ;
    skos:historyNote "WG approval 07/04/2022"@en ;
    skos:prefLabel "has Access URL"@en .

epo:hasAccountingCost a owl:DatatypeProperty ;
    rdfs:isDefinedBy epo:ord ;
    skos:definition "The accounting reference used by the Buyer to specify the account to which the order and the corresponding invoice are booked. (epo-ord:Order) The accounting reference used by the Buyer to specify the account to which the order and the corresponding invoice are booked. (epo-ord:OrderLine)"@en ;
    skos:historyNote "WG Approval 26/01/2023"@en ;
    skos:prefLabel "has Accounting Cost"@en .

epo:hasActualDeliveryDate a owl:DatatypeProperty ;
    rdfs:isDefinedBy epo:ord ;
    skos:definition "The date when the Delivery occured. (epo-ord:DeliveryInformation)"@en ;
    skos:historyNote "WG approval 25/09/2026"@en ;
    skos:prefLabel "has Actual Delivery Date"@en .

epo:hasAllowanceChargeReason a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:ord ;
    skos:definition "The justification for using the Allowance or the Charge."@en ;
    skos:prefLabel "has Allowance Charge Reason"@en .

epo:hasAllowanceChargeReasonDescription a owl:DatatypeProperty ;
    rdfs:isDefinedBy epo:ord ;
    skos:definition "Explanatory text about the motive of the Allowance Charge. (epo-ord:AllowanceChargeInformation)"@en ;
    skos:historyNote "WG approval 25/09/2026"@en ;
    skos:prefLabel "has Allowance Charge Reason Description"@en .

epo:hasAmount a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:ord ;
    skos:definition "The predetermined monetary value charged in addition to the price."@en ;
    skos:historyNote "WG Approval 26/07/2022"@en ;
    skos:prefLabel "has Amount"@en .

epo:hasAmountDueForPayment a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:ord ;
    skos:definition "Relation indicating the Monetary Value that has to be paid."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "has Amount Due For Payment"@en .

epo:hasBackorderQuantity a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:ord ;
    skos:definition "Relation indicating the number of Items that cannot be fulfilled immediately."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "has Backorder Quantity"@en .

epo:hasDeliveryDeadline a owl:DatatypeProperty ;
    rdfs:isDefinedBy epo:ord ;
    skos:definition "The final accepted date for Delivery. (epo-ord:DeliveryInformation)"@en ;
    skos:historyNote "WG approval 25/09/2026"@en ;
    skos:prefLabel "has Delivery Deadline"@en .

epo:hasDeliveryEmail a owl:DatatypeProperty ;
    rdfs:isDefinedBy epo:ord ;
    skos:definition "The electronic address to which the products or services are to be delivered. (epo-ord:DeliveryInformation)"@en ;
    skos:historyNote "WG approval 03/04/2025"@en ;
    skos:prefLabel "has Delivery Email"@en .

epo:hasDeliveryPeriod a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:ord ;
    skos:definition "Relation indicating the time range for the delivery."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "has Delivery Period"@en .

