    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "has Total Debit Amount"@en .

epo:hasTotalPaymentAmount a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:pay ;
    skos:definition "Relation indicating the overall paid Monetary Value."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "has Total Payment Amount"@en .

epo:refersToInvoice a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:pay ;
    skos:definition "Reference to an Invoice."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "refers To Invoice"@en .

epo:specifiesBuyer a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:pay ;
    skos:definition "Relation indicating that the instance of the concept involves the Buyer."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "specifies Buyer"@en .

epo:specifiesPayee a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:pay ;
    skos:definition "Relation indicating that the instance of the concept involves the Payee."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "specifies Payee"@en .

epo:specifiesSeller a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:pay ;
    skos:definition "Relation indicating that the instance of the concept involves the Seller."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "specifies Seller"@en .

epo:pay a owl:Ontology ;
    rdfs:label "eProcurement Ontology Payment - core"@en ;
    dcterms:created "2021-06-01"^^xsd:date ;
    dcterms:description "The eProcurement Ontology Payment core describes the concepts and properties representing the European Public Procurement Payment domain. The provision of these semantics offers the basis for a common understanding of the domain for all stakeholders ensuring the quality of data exchange and transparency. The ontology restrictions are published in a separate artefact."@en ;
    dcterms:issued "2025-10-10"^^xsd:date ;
