# ---- Source module: ePO_core.ttl ----
@prefix dcterms: <http://purl.org/dc/terms/> .
@prefix epo: <http://data.europa.eu/a4g/ontology#> .
@prefix foaf: <http://xmlns.com/foaf/0.1/> .
@prefix org: <http://www.w3.org/ns/org#> .
@prefix owl: <http://www.w3.org/2002/07/owl#> .
@prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#> .
@prefix skos: <http://www.w3.org/2004/02/skos/core#> .
@prefix vann: <http://purl.org/vocab/vann/> .
@prefix xsd: <http://www.w3.org/2001/XMLSchema#> .

epo:AccessTerm a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:Term ;
    skos:definition "Conditions and stipulations about where and how to access the Procurement Documents."@en ;
    skos:historyNote "WG Approval 09/03/2021"@en ;
    skos:prefLabel "Access Term"@en .

epo:AcquiringCentralPurchasingBody a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:CentralPurchasingBody ;
    skos:definition "Role of an Agent procuring activities conducted on a permanent basis in the form of the acquisition of supplies and/or services intended for other Buyers. Additional Information: In Public Procurement the Role of Acquiring Central Purchasing Body is carried out by a Central Purchasing Body for other Contracting Authorities."@en ;
    skos:historyNote "WG approval 05/08/2021"@en ;
    skos:prefLabel "Acquiring Central Purchasing Body"@en .

epo:AdHocChannel a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf <http://data.europa.eu/m8g/Channel> ;
    skos:definition "Web page where tools and devices for electronic communication that are not generally available can be downloaded free of charge."@en ;
    skos:editorialNote "Used by eForms BT-724"@en ;
    skos:historyNote "WG Approval 10/01/2023"@en ;
    skos:prefLabel "Ad Hoc Channel"@en .

epo:Asset a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Resource necessary for the provision of a service."@en ;
    skos:historyNote "WG approval 09/10/2025"@en ;
    skos:prefLabel "Asset"@en .

epo:AuxiliaryParty a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:AgentInRole ;
    skos:definition "Role of an Agent who may be mentioned in the information exchanged during the Procurement Process but who does not play an active part in it."@en ;
    skos:prefLabel "Auxiliary Party"@en .

epo:AwardCriteriaSummary a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:ProcurementCriteriaSummary ;
    skos:definition "Overview of the Award Criteria."@en ;
    skos:historyNote "WG approval 19/03/2024"@en ;
    skos:prefLabel "Award Criteria Summary"@en .

epo:AwardCriterion a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:MaskableObject,
        epo:ProcurementCriterion ;
    skos:definition "Criterion that describes a Requirement that the Tender needs to resolve and on which the Tender is evaluated and ranked."@en ;
    skos:historyNote "WG Approval 05/11/2018"@en ;
    skos:prefLabel "Award Criterion"@en .

epo:AwardDecision a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Resolution of the Buyer as to the result of the Procurement Procedure."@en ;
    skos:historyNote "WG Approval 14/11/2018"@en ;
    skos:prefLabel "Award Decision"@en .

epo:AwardEvaluationTerm a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:EvaluationTerm,
        epo:MaskableObject ;
    skos:definition "Conditions and stipulations defining particularities of the evaluation of Award Criteria."@en ;
    skos:prefLabel "Award Evaluation Term"@en .

epo:Awarder a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:AcquiringParty ;
    skos:definition "A Role of an Agent that signs the Award Decision. Additional information: BT-08 can be Awarding CBP; BG-03 is the Buyer. But Awarding CPB is not the same as the Buyer; the organisations may differ for these roles. Having the Awarder Role allows us to specify which Organisation is involved in the Award Decision."@en ;
    skos:prefLabel "Awarder"@en .

epo:AwardingCentralPurchasingBody a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:CentralPurchasingBody ;
    skos:definition "Role of an Agent procuring activities conducted on a permanent basis in the form of the award of Public Contracts or the conclusion of Framework Agreements for works, supplies or services intended for other Buyers. Additional Information: In Public Procurement the Role of Awarding Central purchasing Body is carried out by a Central Purchasing Body for other Contracting Authorities."@en ;
    skos:historyNote "WG approval 05/08/2021"@en ;
    skos:prefLabel "Awarding Central Purchasing Body"@en .

epo:BudgetProvider a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:AcquiringParty ;
    skos:definition "A role of an agent whose Budget is used to pay for the Contract."@en ;
    skos:prefLabel "Budget Provider"@en .

epo:Business a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf org:Organization ;
    skos:definition "A private law company registered in a national registry."@en ;
    skos:historyNote "WG Approval 28/04/2020"@en ;
    skos:prefLabel "Business"@en .

epo:Candidate a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:OfferingParty ;
    skos:definition "The Role of an Agent that has sought an invitation or has been invited to take part in a restricted Procedure, in a competitive Procedure with negotiation, in a negotiated Procedure without prior publication, in a competitive dialogue or in an innovation partnership."@en ;
    skos:historyNote "WG approval 30/05/2023"@en ;
    skos:prefLabel "Candidate"@en .

epo:CatalogueProvider a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:OfferingParty ;
    skos:definition "A Role of an Agent compiling and supplying a Catalogue. Additional Information: The Catalogue Provider Role is usually played by the Agent that acts as a Seller, or by another Agent that acts on behalf of the Seller."@en ;
    skos:historyNote "WG Approval 28/01/2021"@en ;
    skos:prefLabel "Catalogue Provider"@en .

epo:CatalogueReceiver a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:AcquiringParty ;
    skos:definition "A Role of an Agent processing a Catalogue. Additional Information: The Catalogue Receiver may not only receive it but also validate it, process it, etc. The Catalogue Receiver role is usually played by the agent that acts as a Buyer, or by another Agent that acts on behalf of the Buyer."@en ;
    skos:historyNote "WG Approval 28/01/2021"@en ;
    skos:prefLabel "Catalogue Receiver"@en .

epo:Certificate a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf <http://data.europa.eu/m8g/Evidence> ;
    skos:definition "Proof of conformance of the instance of the concept to a defined set of criteria. Additional Information: Certificates provide assurance of credibility, trust, and transparency in the procurement process."@en ;
    skos:historyNote "WG approval 16/05/2023"@en ;
    skos:prefLabel "Certificate"@en .

epo:CertificationLabel a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf <http://data.europa.eu/m8g/InformationConcept> ;
    skos:definition "Concept that stands for a set of norms, expectations, standards and policies. Additional Information: Such standards may relate to social, ethical and quality etc."@en ;
    skos:historyNote "WG approval 26/07/2022"@en ;
    skos:prefLabel "Certification Label"@en .

epo:Certifier a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "The role of an agent who issues a certificate. Additional Information: The certifier is responsible for verifying and confirming the conformance of the instance of the concept to a defined set of criteria."@en ;
    skos:historyNote "WG approval 16/05/2023"@en ;
    skos:prefLabel "Certifier"@en .

epo:ChangeInformation a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:ContextDescription ;
    skos:definition "Alteration to previously provided details."@en ;
    skos:prefLabel "Change Information"@en .

epo:CleanVehicleDirectiveInformation a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:ContextDescription ;
    skos:definition "Information related to clean vehicles legislation. Additional information: In the European Union, the legislation concerned is the European Parliament and Council 2009/33/EC (Clean Vehicles Directive – CVD)."@en ;
    skos:historyNote "WG approval 07/05/2024"@en ;
    skos:prefLabel "Clean Vehicle Directive Information"@en .

epo:ConcessionContract a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:Contract ;
    skos:definition "A Contract between one or more Buyers and one or more Economic Operators giving the right to the Economic Operators to exploit the rights foreseen in the Contract which may include the receipt of Payments."@en ;
    skos:historyNote "WG Approval 24/05/2022"@en ;
    skos:prefLabel "Concession Contract"@en .

epo:ConcessionEstimate a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:Estimate,
        epo:MaskableObject ;
    skos:definition "Approximation concerning the foreseen Concession Contract."@en ;
    skos:historyNote "WG approval 19/03/2024"@en ;
    skos:prefLabel "Concession Estimate"@en .

epo:ContractLotCompletionInformation a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:ContextDescription ;
    skos:definition "Information related to a given Lot at the end of the procurement."@en ;
    skos:prefLabel "Contract Lot Completion Information"@en .

epo:ContractTerm a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:Term ;
    skos:definition "Conditions and stipulations defining particularities of the Post Award Phase."@en ;
    skos:historyNote "WG approval 23/11/2018"@en ;
    skos:prefLabel "Contract Term"@en .

epo:Contractor a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:OfferingParty ;
    skos:definition "The Role of an Agent that has signed a Contract with a Buyer."@en ;
    skos:historyNote "WG approval 08/11/2022"@en ;
    skos:prefLabel "Contractor"@en .

epo:DesignContestRegimeTerm a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:Term ;
    skos:definition "Conditions and stipulations defining particularities of a Design Contest."@en ;
    skos:historyNote "WG approval 04/02/2021"@en ;
    skos:prefLabel "Design Contest Regime Term"@en .

epo:DirectAwardTerm a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:MaskableObject,
        epo:Term ;
    skos:definition "Conditions and stipulations defining particularities of the award of a Contract without prior publication. Addtional Information: Direct award may refer to a previous Procedure and/or specific Lot(s). It may also refer to other justified situations whereby there is no previous Procedure. See Directive 2014/24/EU Article 32."@en ;
    skos:historyNote "WG Approval 22/11/2019"@en ;
    skos:prefLabel "Direct Award Term"@en .

epo:DirectContract a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:Contract ;
    skos:definition "A Contract resulting from Lot Award Outcome. Additional information: A Framework Agreement is not a Direct Contract."@en ;
    skos:historyNote "WG Approval 19/03/2024"@en ;
    skos:prefLabel "Direct Contract"@en .

epo:Document a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "A set of interrelated Business Information representing the Business facts and associated metadata. The information may be conveyed in any language, medium or form, including textual, numerical, graphic, cartographic, audio-visual forms, etc."@en ;
    skos:historyNote "WG approval 23/05/2019"@en ;
    skos:prefLabel "Document"@en .

epo:DynamicPurchaseSystemTechnique a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:Technique ;
    skos:definition "A Technique that allows the selection of Candidates throughout the Procedure via the Qualification Criteria, followed by individual Mini-Competitions for the Award of Purchase Contracts."@en ;
    skos:historyNote "WG approval 23/05/2023"@en ;
    skos:prefLabel "Dynamic Purchase System Technique"@en .

epo:EAuctionTechnique a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:Technique ;
    skos:definition "A repetitive Technique in which new Prices, revised downwards, and/or new values concerning certain elements of Tenders are bid on-line."@en ;
    skos:editorialNote "Used by eForms BT-767"@en ;
    skos:historyNote "WG approval 20/07/2018"@en ;
    skos:prefLabel "E Auction Technique"@en .

epo:EconomicStandingSummary a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:SelectionCriteriaSummary ;
    skos:definition "Overview of the financial viability of the economic operator."@en ;
    skos:historyNote "WG approval 19/03/2024"@en ;
    skos:prefLabel "Economic Standing Summary"@en .

epo:ElectronicSignature a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Data in electronic form which is attached to or logically associated with other data in electronic form and which is used by the signatory to sign. Additional information: The definition comes from REGULATION (EU) No 910/2014."@en ;
    skos:historyNote "WG approval 19/03/2024"@en ;
    skos:prefLabel "Electronic Signature"@en .

epo:EmploymentDocumentation a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:Documentation ;
    skos:definition "Documentation concerning the general regulatory framework for employment protection and working conditions."@en ;
    skos:historyNote "WG approval 11/09/2025"@en ;
    skos:prefLabel "Employment Documentation"@en .

epo:EmploymentInformationProvider a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "A Role of an Agent responsible for providing information concerning the general regulatory framework for employment protection and working conditions applicable in the place where the contract is to be performed."@en ;
    skos:prefLabel "Employment Information Provider"@en .

epo:EnergyEfficiencyInformation a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:ContextDescription ;
    skos:definition "Information about the energy performance, consumption, or sustainability characteristics of a product, service, building, or process relevant to the execution or evaluation of a procurement procedure."@en ;
    skos:historyNote "WG approval 11/09/2025"@en ;
    skos:prefLabel "Energy Efficiency Information"@en .

epo:EnvironmentalDocumentation a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:Documentation ;
    skos:definition "Documentation concerning the general regulatory framework for Environmental Protection."@en ;
    skos:historyNote "WG approval 11/09/2025"@en ;
    skos:prefLabel "Environmental Documentation"@en .

epo:EnvironmentalProtectionInformationProvider a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "A Role of an Agent responsible for providing information concerning the general regulatory framework for Environmental Protection applicable in the place where the contract is to be performed."@en ;
    skos:prefLabel "Environmental Protection Information Provider"@en .

epo:ExclusionGround a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:QualificationCriterion ;
    skos:definition "Criterion that describes a legal Requirement to be met by the Economic Operator to be a Candidate in the Procurement."@en ;
    skos:editorialNote "Used by eForms BG-701"@en ;
    skos:historyNote "WG Approval 31/10/2018"@en ;
    skos:prefLabel "Exclusion Ground"@en .

epo:ExclusionGroundsSummary a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:QualificationCriteriaSummary ;
    skos:definition "Overview of the Exclusion Grounds."@en ;
    skos:historyNote "WG approval 19/03/2024"@en ;
    skos:prefLabel "Exclusion Grounds Summary"@en .

epo:ExpressionOfInterest a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Document presenting an Economic Operator's Request to be considered for Procedures covering a specific domain."@en ;
    skos:historyNote "WG approval 13/04/2021"@en ;
    skos:prefLabel "Expression Of Interest"@en .

epo:FrameworkAgreement a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:Contract ;
    skos:definition "An agreement between one or more Contracting Authorities and one or more Economic Operators. Additional Information: When a Framework Agreement is concerned, the FA will result from LotAwardOutcome which describes a Lot which specifies the both the Qualification and Award Criteria."@en ;
    skos:historyNote "WG Approval 18/05/2021"@en ;
    skos:prefLabel "Framework Agreement"@en .

epo:FrameworkAgreementTechnique a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:Technique ;
    skos:definition "Technique that establishes the terms governing Contracts to be awarded during a given Period, in particular with regard to Price and, where appropriate, the Quantity envisaged."@en ;
    skos:historyNote "WG approval 18/05/2021"@en ;
    skos:prefLabel "Framework Agreement Technique"@en .

epo:FrameworkAgreementTerm a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:Term ;
    skos:definition "Conditions and stipulations defining particularities in a Framework Agreement."@en ;
    skos:prefLabel "Framework Agreement Term"@en .

epo:Fund a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "A financial resource used to support the Procurement. Additional Information: In the context of EU, Funds can be divided into programmes, actions and projects. Examples of EU funds are: the European Structural and Investment Funds, European Social Fund (ESF), the Connecting Europe Facility (CEF) programme, or the ISA2 programme and its actions (e.g. Action 2016.05 European Public Procurement Initiative, which supports the eProcurement Ontology under sub-action 3). Funds may change between the lot and the contract, for example in the case of an emergency crisis, a contract may be financed by a budget that was not foreseen in the call."@en ;
    skos:historyNote "WG Approval 14/05/2019"@en ;
    skos:prefLabel "Fund"@en .

epo:GreenProcurement a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:StrategicProcurement ;
    skos:definition "Approach whereby Buyers seek to procure with a reduced Environmental Impact. Additional Information: The approach may apply to the complete life cycle. The reduced Environmental Impact is in comparison to goods, services and works with the same primary function that would otherwise be procured. Tightly related are article 68 - Life-cycle costing and article 67 - most economically advantageous Tender (see GPP handbook) https://ec.europa.eu/environment/gpp/pdf/Buying-Green-Handbook-3rd-Edition.pdf An instance of the class GreenProcurement is represented in eForms with the code \"env-imp\" defined in the codelist Strategic-Procurement.Paragraphs) https://ec.europa.eu/environment/gpp/pdf/Buying-Green-Handbook-3rd-Edition.pdf"@en ;
    skos:prefLabel "Green Procurement"@en .

epo:InnovativeProcurement a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:StrategicProcurement ;
    skos:definition "Approach whereby Buyers seek to procure an innovative work, supply or service. Additional Information: ‘innovation’ means the implementation of a new or significantly improved product, service or process, including but not limited to production, building or construction processes, a new marketing method, or a new organizational method in business practices, workplace Organisation or external relations inter alia with the purpose of helping to solve societal challenges or to support the Europe 2020 strategy for smart, sustainable and inclusive growth; See: Directive 2014/24 Articles: 2, 26 (3), 31, 67 (2.a)"@en ;
    skos:prefLabel "Innovative Procurement"@en .

epo:InternationalProcurementInstrumentMeasuresInformation a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:ContextDescription ;
    skos:definition "Information about the legislative framework adopted by the European Union to promote reciprocity in international public procurement markets."@en ;
    skos:historyNote "WG approval 11/09/2025"@en ;
    skos:prefLabel "International Procurement Instrument Measures Information"@en .

epo:JuryMember a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:AcquiringParty ;
    skos:definition "Role of an Agent who evaluates a design contest."@en ;
    skos:historyNote "WG approval 19/03/2024"@en ;
    skos:prefLabel "Jury Member"@en .

epo:LeadBuyer a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:Buyer ;
    skos:definition "A Role of an Agent who is a Buyer and takes the administrative lead of the Procedure."@en ;
    skos:historyNote "WG Approval 22/11/2022"@en ;
    skos:prefLabel "Lead Buyer"@en .

epo:LocalLegalBasisInformation a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Information about the legal basis at the level of the Member State."@en ;
    skos:historyNote "WG approval 11/09/2025"@en ;
    skos:prefLabel "Local Legal Basis Information"@en .

epo:Lot a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:ProcurementObject ;
    skos:definition "A qualitative, quantitative or strategic subdivision of the goods, services or works to be procured, allowing the award of one or more Contracts."@en ;
    skos:historyNote "WG approval 12/09/2018"@en ;
    skos:prefLabel "Lot"@en .

epo:LotAwardOutcome a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:AwardOutcome,
        epo:MaskableObject ;
    skos:definition "Result concerning the Lot that was attributed by the Awarder."@en ;
    skos:historyNote "WG Approval 19/03/2024"@en ;
    skos:prefLabel "Lot Award Outcome"@en .

epo:LotGroup a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Combination of several Lots to conduct comparative assessment of the Tenders. Additional Information: The comparative assessment may refer to the Selection Criteria, Award and Value that apply to several Lots. Pending of discussion with eForms Member States may provide that, where more than one lot may be awarded to the same tenderer, contracting authorities may award contracts combining several or all lots where they have specified in the contract notice or in the invitation to confirm interest that they reserve the possibility of doing so and indicate the lots or groups of lots that may be combined."@en ;
    skos:prefLabel "Lot Group"@en .

epo:LotGroupAwardInformation a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:ContextDescription ;
    skos:definition "Award information related to a given Group of Lots."@en ;
    skos:prefLabel "Lot Group Award Information"@en .

epo:Mediator a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:AcquiringParty ;
    skos:definition "A Role of an Agent that attempts to resolve a dispute between different Agents and come to an agreement."@en ;
    skos:historyNote "WG approval 20/04/2021"@en ;
    skos:prefLabel "Mediator"@en .

epo:MiniCompetitionAwardOutcome a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:AwardOutcome ;
    skos:definition "Result concerning the mini-competition that was attributed by the Awarder. Additional Information: The mini-competition is the process where multiple winners or candidates of previous stages of a procedure bid for a specific procurement. It is typically used in framework agreements where the suppliers have already been pre-selected, and the mini competition is used to determine which supplier is best suited for a particular project or contract. It is also used in a Dynamic Purchasing System where the suppliers come from a list of Candidates."@en ;
    skos:historyNote "WG Approval 19/03/2024"@en ;
    skos:prefLabel "Mini Competition Award Outcome"@en .

epo:MonetaryValue a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:MaskableObject ;
    skos:definition "A number of monetary units specified using a given unit of currency. Additional information: In the pre-award phase of the procurement, all monetary values are considered to exclude VAT based on the Directive 2014/24/EU."@en ;
    skos:historyNote "WG approval 13/04/2021"@en ;
    skos:prefLabel "Monetary Value"@en .

epo:MultipleStageProcedureTerm a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:Term ;
    skos:definition "Conditions and stipulations defining particularities of Procedures carried out in several steps Additional Information: Generally this refers to Procedures where selection is carried out to qualify Tenderers who are then requested to submit the rest of their Tender for evaluation is Restricted Procedure."@en ;
    skos:historyNote "WG Approval 15/04/2021"@en ;
    skos:prefLabel "Multiple Stage Procedure Term"@en .

epo:NonDisclosureAgreementTerm a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:Term ;
    skos:definition "Conditions and stipulations about a non-disclosure agreement. Additional information: A non-disclosure agreement is a Contract between different parties which ensures information is not shared with other parties."@en ;
    skos:historyNote "WG approval 26/03/2024"@en ;
    skos:prefLabel "Non Disclosure Agreement Term"@en .

epo:NonPublishedInformation a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:ContextDescription ;
    skos:definition "Information about fields not published in this Notice. Additional Information: The non-published information may become available at a later date and may differ from one element to another within a given Document. Examples of fields that may not be immediately published are Winner, Tender and Procedure Lot Result, etc., e.g. for security reasons."@en ;
    skos:prefLabel "Non Published Information"@en .

epo:Notice a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Document published by the Buyer about market opportunities and results."@en ;
    skos:historyNote "WG Approval 23/05/2019"@en ;
    skos:prefLabel "Notice"@en .

epo:NoticeAwardInformation a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:ContextDescription ;
    skos:definition "Information about an Award Notice."@en ;
    skos:prefLabel "Notice Award Information"@en .

epo:Offer a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Document providing the Monetary Value and the details to fulfill the Requirements set out in the Procurement Documents or Request for Offer. Additional information: A quotation is considered to be an Offer in the eProcurement Ontology."@en ;
    skos:historyNote "WG approval 09/02/2023"@en ;
    skos:prefLabel "Offer"@en .

epo:OfferIssuer a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:OfferingParty ;
    skos:definition "The Role of an Agent that distributes an Offer."@en ;
    skos:historyNote "WG approval 09/02/2023"@en ;
    skos:prefLabel "Offer Issuer"@en .

epo:OfflineAccessProvider a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:AcquiringParty ;
    skos:definition "A Role of an Agent responsible for providing offline access to the Procurement Documents."@en ;
    skos:prefLabel "Offline Access Provider"@en .

epo:OpeningTerm a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:Term ;
    skos:definition "Conditions and stipulations defining particularities of the opening of Tenders. Additional Information: The opening of Tenders is the event when Tenders are made accessible for evaluation, it is generally the same date and time for all Tenders."@en ;
    skos:historyNote "WG Approval 15/04/2021"@en ;
    skos:prefLabel "Opening Term"@en .

epo:OrganisationGroup a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf org:Organization ;
    skos:definition "Agreed collaboration of several Organisations. Additional Information: This concept has been created to fulfill the need to represent a grouping of Organisations that is not necessarily registered i.e, consortia."@en ;
    skos:historyNote "WG approval 15/04/2021"@en ;
    skos:prefLabel "Organisation Group"@en .

epo:OriginatorRequest a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Document in which the Originator describes his needs."@en ;
    skos:historyNote "WG approval 09/02/2023"@en ;
    skos:prefLabel "Originator Request"@en .

epo:ParticipationCondition a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:ProcurementCriterion ;
    skos:definition "Criterion that describes a Requirement to take part in a procurement."@en ;
    skos:historyNote "WG approval 30/05/2023"@en ;
    skos:prefLabel "Participation Condition"@en .

epo:ParticipationConditionsSummary a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:ProcurementCriteriaSummary ;
    skos:definition "Overview of the Participation Conditions."@en ;
    skos:historyNote "WG approval 19/03/2024"@en ;
    skos:prefLabel "Participation Conditions Summary"@en .

epo:ParticipationRequestProcessor a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:AcquiringParty ;
    skos:definition "A Role of an Agent responsible for processing Requests To Participate."@en ;
    skos:prefLabel "Participation Request Processor"@en .

epo:ParticipationRequestReceiver a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:AcquiringParty ;
    skos:definition "A Role of an Agent responsible for receiving Requests To Participate."@en ;
    skos:prefLabel "Participation Request Receiver"@en .

epo:ParticipationRequestTerm a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:Term ;
    skos:definition "Conditions and stipulations defining particularities of requesting participation in a Procedure."@en ;
    skos:prefLabel "Participation Request Term"@en .

epo:PaymentExecutor a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:AcquiringParty ;
    skos:definition "A Role of an Agent responsible for executing the Payment."@en ;
    skos:prefLabel "Payment Executor"@en .

epo:PlannedProcurement a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:ProcurementElement ;
    skos:definition "A high-level description of a procurement activity foreseen by a Buyer."@en ;
    skos:historyNote "WG approval 11/09/2025"@en ;
    skos:prefLabel "Planned Procurement"@en .

epo:PlannedProcurementPart a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:ProcurementElement ;
    skos:definition "A subdivision of a Planned Procurement that may later become one or more Lots or a self-standing Procedure. Additional Information: A Lot or a Procedure can also cover one or more parts of the Planned Procurement."@en ;
    skos:historyNote "WG Approval 20/06/2019"@en ;
    skos:prefLabel "Planned Procurement Part"@en .

epo:Prize a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "A reward given in a Contest."@en ;
    skos:historyNote "WG approval: 15/04/2021"@en ;
    skos:prefLabel "Prize"@en .

epo:Procedure a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:ProcurementObject ;
    skos:definition "A legally defined set of administrative activities conducted to conclude one or more Contracts. Additional Information The Procedure is categorised in the law according to different rules determining whether the Procedure is Open, Restricted, Negotiated with or without publicity, etc. (see Procedure Type)."@en ;
    skos:historyNote "WG Approval 20/08/2019"@en ;
    skos:prefLabel "Procedure"@en .

epo:ProcedureTerm a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:MaskableObject,
        epo:Term ;
    skos:definition "Conditions and stipulations defining particularities of the Procedure."@en ;
    skos:historyNote "WG approval 23/11/2018"@en ;
    skos:prefLabel "Procedure Term"@en .

epo:ProcessPlanningTerm a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:Term ;
    skos:definition "Conditions and stipulations defining particularities of the unfolding of the Procurement Process."@en ;
    skos:prefLabel "Process Planning Term"@en .

epo:ProcurementDocument a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Document produced or referred to by the Buyer to describe or determine elements of the Procurement. Additional information: Procurement Documents are to be accessible since the date of publication of the Contract Notice or the prior information Notice when used as a call for competition. Examples of Procurement Documents are Technical Specifications, the Descriptive Document, proposed conditions of Contract, formats for the presentation of Documents by Candidates and Tenderers, information on generally applicable obligations. Other Documents related to the Procedure such as Notices are not considered to be Procurement Documents."@en ;
    skos:historyNote "WG Approval 23/05/2019"@en ;
    skos:prefLabel "Procurement Document"@en .

epo:ProcurementProcedureInformationProvider a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:AcquiringParty ;
    skos:definition "A Role of an Agent responsible for providing additional information about the Procurement Procedure."@en ;
    skos:prefLabel "Procurement Procedure Information Provider"@en .

epo:ProcurementProcessInformation a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:ContextDescription ;
    skos:definition "Information about the temporal unfolding or succession of Procurement Objects."@en ;
    skos:prefLabel "Procurement Process Information"@en .

epo:ProcurementServiceProvider a owl:Class ;
    dcterms:source "Directive 2014/24/EU, Article 2, paragraphs 17 and 15."@en ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:AcquiringParty ;
    skos:definition "Role of a public or private body which offers ancillary purchasing activities on the market. Additional information: \"Ancillary Purchasing Activities\" means activities consisting in the provision of support to purchasing activities, in particular in the following forms: (a) technical infrastructure enabling Contracting Authorities to award Public Contracts or to conclude Framework Agreements for works, supplies or services; (b) advice on the conduct or design of public Procurement Procedures; (c) preparation and management of Procurement Procedures on behalf and for the account of the Contracting Authority concerned; This would be equivalent to the concept of 'ProcuringEntity' in OCDS: 'The Entity managing the Procurement, which may be different from the Buyer who is paying / using the items being procured'."@en ;
    skos:historyNote "WG Approval 24/03/2020"@en ;
    skos:prefLabel "Procurement Service Provider"@en .

epo:ProfessionalSuitabilitySummary a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:SelectionCriteriaSummary ;
    skos:definition "Overview of the professional ability required for the economic operator to execute the contract."@en ;
    skos:historyNote "WG approval 19/03/2024"@en ;
    skos:prefLabel "Professional Suitability Summary"@en .

epo:Project a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "A collaborative enterprise that is carefully planned to achieve a particular aim."@en ;
    skos:prefLabel "Project"@en .

epo:PurchaseContract a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:Contract ;
    skos:definition "A Contract resulting from using a Dynamic Purchasing System Technique or Framework Agreement Technique."@en ;
    skos:prefLabel "Purchase Contract"@en .

epo:Purpose a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "The description of the objectives related to a Procurement. Additional information: The description of the objectives includes the Subject Matter and Quantities. The quantification of the objectives related to a procurement. To be re-reviewed by the WG the soonest. (WG to be discussed, this was pointed out on the 09/04/2019 14:38:25 WG Meeting) The old definition read as follows: The description of the objectives related to a procurement."@en ;
    skos:historyNote "WG approval 05/12/2018"@en ;
    skos:prefLabel "Purpose"@en .

epo:QualityTargetInformation a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:ContextDescription ;
    skos:definition "Information about a specific performance goal."@en ;
    skos:historyNote "WG approval 23/09/2025"@en ;
    skos:prefLabel "Quality Target Information"@en .

epo:Quantity a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "A counted number of non-monetary units possibly including fractions."@en ;
    skos:prefLabel "Quantity"@en .

epo:ReliedUponEntity a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:OfferingParty ;
    skos:definition "Economic Operator (who is not a Subcontractor) on which the Tenderer relies upon, to meet Selection Criteria."@en ;
    skos:prefLabel "Relied Upon Entity"@en .

epo:ReviewDecision a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Information about Review Decisions."@en ;
    skos:prefLabel "Review Decision"@en .

epo:ReviewInformation a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Information about the Review Decision or the Review Request."@en ;
    skos:historyNote "WG approval 11/09/2025"@en ;
    skos:prefLabel "Review Information"@en .

epo:ReviewIrregularitySummary a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:MaskableObject,
        epo:StatisticalInformation ;
    skos:definition "Overview of the number and type of requests the Buyer received to review any of its decisions (e.g. the Technical Specifications, Award Decision)."@en ;
    skos:historyNote "WG approval 19/03/2024"@en ;
    skos:prefLabel "Review Irregularity Summary"@en .

epo:ReviewProcedureInformationProvider a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:AcquiringParty ;
    skos:definition "A Role of an Agent who is providing more information on the time limits for review Procedures."@en ;
    skos:prefLabel "Review Procedure Information Provider"@en .

epo:ReviewRequest a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Information about requests to review procedures."@en ;
    skos:historyNote "WG Approval 23/10/2021"@en ;
    skos:prefLabel "Review Request"@en .

epo:ReviewRequestSummary a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:MaskableObject,
        epo:StatisticalInformation ;
    skos:definition "Overview of the requests received by the Buyer to review any of its decisions (e.g. the technical specifications, award decision), as set out in Art. 1(5) of Directive 89/665/EEC and Directive 92/13/EEC, and about the complainants that submitted the requests."@en ;
    skos:historyNote "WG approval 19/03/2024"@en ;
    skos:prefLabel "Review Request Summary"@en .

epo:ReviewRequester a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:OfferingParty ;
    skos:definition "Role of an Agent who requests the review of a (Procurement) Procedure."@en ;
    skos:historyNote "WG Approval 23/10/2021"@en ;
    skos:prefLabel "Review Requester"@en .

epo:ReviewTerm a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:Term ;
    skos:definition "Conditions and stipulations defining particularities of the review."@en ;
    skos:historyNote "WG approval 23/11/2018"@en ;
    skos:prefLabel "Review Term"@en .

epo:Reviewer a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:AcquiringParty ;
    skos:definition "Role of an Agent who investigates the overall correctness of a Procurement Procedure, producing a related report. Additional Information: Any Organisation or Person may request a review of a Procurement Procedure."@en ;
    skos:historyNote "WG approval 20/04/2021"@en ;
    skos:prefLabel "Reviewer"@en .

epo:SecurityClearanceTerm a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:Term ;
    skos:definition "Conditions and stipulations about the status requested of individuals allowing them access to classified information (state or organisational secrets) or to restricted areas, after completion of a thorough background check."@en ;
    skos:editorialNote "Used by eForms BT-578, eForms BT-78, eForms BT-732"@en ;
    skos:historyNote "WG Approval 20/06/2023"@en ;
    skos:prefLabel "Security Clearance Term"@en .

epo:SelectedCandidateList a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Record of Candidates admitted to take part in award phases of procurements."@en ;
    skos:historyNote "WG approval 30/05/2023"@en ;
    skos:prefLabel "Selected Candidate List"@en .

epo:SelectionCriterion a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:QualificationCriterion ;
    skos:definition "Criterion that describes a capacity Requirement that the Economic Operator needs to fulfill to participate in the procurement. Additional Information: Selection criteria may relate to: (a) suitability to pursue the professional activity; (b) economic and financial standing; (c) technical and professional ability"@en ;
    skos:historyNote "WG approval 31/10/2018"@en ;
    skos:prefLabel "Selection Criterion"@en .

epo:SelectionEvaluationTerm a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:EvaluationTerm ;
    skos:definition "Conditions and stipulations defining particularities of the evaluation of Selection Criteria."@en ;
    skos:prefLabel "Selection Evaluation Term"@en .

epo:SocialProcurement a owl:Class ;
    dcterms:source """Buying Social - A Guide to Taking Account of Social Considerations in Public Procurement (Publications Office of the European Union, 2011) https://op.europa.eu/en/publication-detail/-/publication/cb70c481-0e29-4040-9be2-c408cddf081f/language-en
"""@en ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:StrategicProcurement ;
    skos:definition "Approach whereby Buyers seek to procure by fulfilling social objectives. Additional Information: Socially Responsible Public Procurement (SRPP) - ‘SRPP’ means Procurement Operations that take into account one or more of the following social considerations: employment opportunities, decent work, compliance with social and labour rights, social inclusion (including persons with disabilities), equal opportunities, accessibility design for all, taking account of sustainability criteria, including ethical trade issues and wider voluntary compliance with corporate social responsibility (CSR), while observing the principles enshrined in the Treaty for the European Union (TFEU) and the Procurement Directives. See Article 18 and Annex X Directive 2014/24."@en ;
    skos:prefLabel "Social Procurement"@en .

epo:SpecificationInformation a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Information about the characteristics and standards used in a technical implementation."@en ;
    skos:historyNote "WG approval 11/09/2025"@en ;
    skos:prefLabel "Specification Information"@en .

epo:SubcontractTerm a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:Term ;
    skos:definition "A concept to describe the main information regarding the share of parts of the Contract to third parties."@en ;
    skos:prefLabel "Subcontract Term"@en .

epo:SubcontractingEstimate a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:Estimate,
        epo:MaskableObject ;
    skos:definition "Approximation concerning the foreseen Subcontracting."@en ;
    skos:historyNote "WG approval 19/03/2024"@en ;
    skos:prefLabel "Subcontracting Estimate"@en .

epo:Subcontractor a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:OfferingParty ;
    skos:definition "A Role of an Agent that has an agreement to perform part or all of the obligations of another Agents's Contract. Additional information For some Procedures, the Subcontractor signs as well the Contract between the Buyer and the Contractor. At tendering time, entities relied upon by the Economic Operators can be Subcontractors or not. When modelling ESPD we will analyze whether we need or not a Role named \"relied upon\"."@en ;
    skos:historyNote "WG approval 05/08/2021"@en ;
    skos:prefLabel "Subcontractor"@en .

epo:SubmissionStatisticalInformation a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:MaskableObject,
        epo:StatisticalInformation ;
    skos:definition "Statistical information about submissions on a given competition, either at Lot level or Mini-Competition level."@en ;
    skos:historyNote "WG approval 30/05/2023"@en ;
    skos:prefLabel "Submission Statistical Information"@en .

epo:SubmissionTerm a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:Term ;
    skos:definition "Conditions and stipulations defining particularities of submitting Documents to the Buyer. Additional Information: These Documents can be Tenders, Request To Participate and expressions of interest."@en ;
    skos:historyNote "WG Approval 14/07/2020"@en ;
    skos:prefLabel "Submission Term"@en .

epo:System a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf foaf:Agent ;
    skos:definition "Software application used for performing Procurement activities."@en ;
    skos:historyNote "WG Approval 28/04/2020"@en ;
    skos:prefLabel "System"@en .

epo:TaxDocumentation a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:Documentation ;
    skos:definition "Documentation concerning the general regulatory framework for taxes."@en ;
    skos:historyNote "WG approval 11/09/2025"@en ;
    skos:prefLabel "Tax Documentation"@en .

epo:TaxInformationProvider a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "A Role of an Agent responsible for providing information concerning the general regulatory framework for taxes applicable in the place where the contract is to be performed."@en ;
    skos:prefLabel "Tax Information Provider"@en .

epo:TechnicalAbilitySummary a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:SelectionCriteriaSummary ;
    skos:definition "Overview of the expertise required for the economic operator to execute the contract."@en ;
    skos:historyNote "WG approval 19/03/2024"@en ;
    skos:prefLabel "Technical Ability Summary"@en .

epo:TechnicalSpecification a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "A set of documented Requirements applicable to the object of the Procurement. Additional Information: A specification often includes technical standards."@en ;
    skos:historyNote "WG approval 20/04/2021"@en ;
    skos:prefLabel "Technical Specification"@en .

epo:Tender a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:MaskableObject ;
    skos:definition "Information submitted by the Economic Operator to specify its Offer regarding a specific Lot, in response to the call for Tender."@en ;
    skos:historyNote "WG approval 03/05/2022"@en ;
    skos:prefLabel "Tender"@en .

epo:TenderAwardOutcome a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:ContextualProjection,
        epo:MaskableObject ;
    skos:definition "Result concerning the Tender attributed by the Awarder."@en ;
    skos:prefLabel "Tender Award Outcome"@en .

epo:TenderGroup a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Specific Offer in response to a Lot Group. Additional Information: This class is generally used to provide the Monetary Value in response to a Lot Group."@en ;
    skos:prefLabel "Tender Group"@en .

epo:TenderProcessor a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:AcquiringParty ;
    skos:definition "A Role of an Agent responsible for processing Tenders."@en ;
    skos:prefLabel "Tender Processor"@en .

epo:TenderReceiver a owl:Class ;
    rdfs:isDefinedBy epo:core ;
