    skos:definition "Relation indicating the instance of a Procurement Object that is planned. Additional Information: The properties of the Procurement Object that is foreseen should be read as foreseen properties. For example, Procedure isSMESuitable should be read as Procedure foreseesToBeSMESuitable. For example, Procedure isFundedBy should be read as Procedure foreseesToBeFundedBy."@en ;
    skos:prefLabel "foresees Procurement Object"@en .

epo:foreseesSubcontracting a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Relation indicating that an instance of the concept plans to be Subcontracted."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "foresees Subcontracting"@en .

epo:foreseesSubcontractor a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Relation indicating that an Organization plans to have a Subcontractor. Additional information: In eForms, in a Result Notice, the foreseen Subcontractors in a Tender are associated to the Organization that proposes the Subcontractors. The Subcontractor is associated to the Organization, rather than the Tenderer, so that, in the case of multiple Organizations being a Tenderer, it is clear to which Organization the proposed Subcontractor is associated."@en ;
    skos:historyNote "WG Approval 26/11/2024"@en ;
    skos:prefLabel "foresees Subcontractor"@en .

epo:foreseesTechnique a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Relation indicating that an instance of the concept plans to apply a Technique."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "foresees Technique"@en .

epo:foreseesTerm a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Relation indicating that an instance of the concept plans to be subject to a Term."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "foresees Term"@en .

epo:fulfillsRequirement a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "The requirement to which the concept meets."@en ;
    skos:prefLabel "fulfills Requirement"@en .

epo:fulfillsStrategicProcurement a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Relation indicating that the concept has a Strategic Procurement goal."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "fulfills Strategic Procurement"@en .

epo:hasAbnormallyLowTenders a owl:DatatypeProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Tenders received that were found irregular and non-acceptable due to an abnormally low price or cost. Additional Information The definition implies that abnormally Low Tender Lots are Inadmissible Tender Lots. (epo:SubmissionStatisticalInformation)"@en ;
    skos:historyNote "WG Approval 28/07/2020"@en ;
    skos:prefLabel "has Abnormally Low Tenders"@en .

epo:hasAcceleratedProcedureJustification a owl:DatatypeProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "The reasons why the procedure is accelerated. Additional Information: A procedure is accelerated to cover needs of extraordinary circumstances ie earthquake relief. (epo:Procedure)"@en ;
    skos:historyNote "WG Approval 09/06/2020"@en ;
    skos:prefLabel "has Accelerated Procedure Justification"@en .

epo:hasAccessURL a owl:DatatypeProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Location where the resource can be accessed. (epo:Document)"@en ;
