    skos:historyNote "WG Approval 12/12/2019"@en ;
    skos:prefLabel "has Inadmissible Tenders"@en .

epo:hasInternalIdentifier a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Relation indicating the in-house Identifier used by an Organization."@en ;
    skos:editorialNote "Used by eForms BT-22"@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "has Internal Identifier"@en .

epo:hasInternationalProcurementInstrumentExceptionInformation a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Relation indicating the International Procurement Instrument Application."@en ;
    skos:prefLabel "has International Procurement Instrument Exception Information"@en .

epo:hasInternetAddress a owl:DatatypeProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "The main web page used by the instance of the concept. (org:Organization) The main web page used by the instance of the concept. (cpov:ContactPoint)"@en ;
    skos:historyNote "WG Approval 01/06/2023"@en ;
    skos:prefLabel "has Internet Address"@en .

epo:hasInvoiceLineObjectIdentifier a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "An identifier for an object on which the invoice line is based, given by the Seller. Additional Information: It may be a subscription number, telephone number, meter point etc., as applicable."@en ;
