epo:hasInvoiceLinePeriod a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Relation indicating the time range of the Invoice Line."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "has Invoice Line Period"@en .

epo:hasInvoicedObjectIdentifier a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "An identifier for an object on which the invoice is based, given by the Seller."@en ;
    skos:prefLabel "has Invoiced Object Identifier"@en .

epo:hasInvoicingPeriod a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Relation indicating the time range for creating, sending, and managing Invoices."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "has Invoicing Period"@en .

epo:hasIrregularityType a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Relation indicating the Irregularity Type."@en ;
    skos:prefLabel "has Irregularity Type"@en .

epo:hasItemClassificationIdentifier a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "The Identifier of the Item categorisation."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "has Item Classification Identifier"@en .

epo:hasItemConsumption a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Relation indicating the amount of resources an Item uses."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "has Item Consumption"@en .

epo:hasItemConsumptionSavings a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Relation indicating the amount of resources an Item saves."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "has Item Consumption Savings"@en .

epo:hasItemCountryOfOrigin a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "The source country of the product or service. Additional Information: The country of origin can be provided by the buyer as a requirement or by the tenderer information of the item to be provided. The codelist to be used is at-voc:country which is available at http://publications.europa.eu/resource/dataset/country"@en ;
    skos:prefLabel "has Item Country Of Origin"@en .

epo:hasItemStandardID a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "The general identifier assigned to the concept based on a standard scheme.​ Additional information: For example the GTIN scheme (Global Trade Item Number)."@en ;
    skos:historyNote "WG Approval 16/05/2023"@en ;
    skos:prefLabel "has Item Standard ID"@en .

epo:hasJuryMember a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "An agent involved in an evaluation board."@en ;
    skos:historyNote "WG Approval 14/09/2021"@en ;
    skos:prefLabel "has Jury Member"@en .

epo:hasJustification a owl:DatatypeProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "An explanation about the reasons for using the concept. (epo:DirectAwardTerm)"@en ;
    skos:historyNote "WG Approval 05/11/2019"@en ;
    skos:prefLabel "has Justification"@en .

epo:hasLabelType a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "The label type such environmental, quality, social etc."@en ;
    skos:prefLabel "has Label Type"@en .

epo:hasLanguage a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Language in which the submitted information is to be expressed."@en ;
    skos:prefLabel "has Language"@en .

epo:hasLateSubmissionInformationDescription a owl:DatatypeProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "A narrative text explaining the content of the economic operator information that can be submitted late. Additional Information This does not apply to requests for clarifications. (epo:SubmissionTerm)"@en ;
    skos:prefLabel "has Late Submission Information Description"@en .

epo:hasLateSubmissionPermission a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Whether economic operator-related information can be supplemented even after the submission deadline. Additional Information This is specific to the information on the economic operator and not the actual offer. This does not apply to the requests for clarification."@en ;
    skos:prefLabel "has Late Submission Permission"@en .

epo:hasLaunchFrameworkAgreementMaximumValue a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Relation indicating that the maximum value allowed for a Framework Agreement as defined by the Buyer at the outset."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "has Launch Framework Agreement Maximum Value"@en .

epo:hasLegalBasis a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "The legal basis under which the procurement procedure takes place. Additional Information: For example European Directives or Regulations, national laws etc. The recommended code list is the example for the legal basis at the European level."@en ;
    skos:prefLabel "has Legal Basis"@en .

epo:hasLegalBasisDescription a owl:DatatypeProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Explanatory text about the legal basis. (epo:ProcurementElement)"@en ;
    skos:historyNote "WG Approval 02/05/2024"@en ;
    skos:prefLabel "has Legal Basis Description"@en .

epo:hasLegalFormRequirement a owl:DatatypeProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "The legal form to be taken by a Contractor. Additional Information: Generally, this is defined to cover the case where an Organisation Group is involved. Note that the codelist provided at national level should be used. (epo:ContractTerm)"@en ;
    skos:prefLabel "has Legal Form Requirement"@en .

epo:hasLegalFormType a owl:DatatypeProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "The classification of an Organisation according to legislation. Additional Information: Generally, this is defined for Tenderers who want to submit as an Organisation Group. Note that the codelist provided at national level should be used. (org:Organization)"@en ;
    skos:prefLabel "has Legal Form Type"@en .

epo:hasLegalIdentifier a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "The officially registered Identifier."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "has Legal Identifier"@en .

epo:hasLegalName a owl:DatatypeProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "The officially registered name of an organisation. (org:Organization)"@en ;
    skos:historyNote "WG Approval 10/01/2023"@en ;
    skos:prefLabel "has Legal Name"@en .

epo:hasLength a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "The horizontal measurement. Additional Information: The length is the longer side between the length and the width."@en ;
    skos:historyNote "WG Approval 18/06/2024"@en ;
    skos:prefLabel "has Length"@en .

epo:hasLoadingMeter a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "The area of the Consignment in meters divided by the width of the truck, which is considered to be 2.4 meters."@en ;
    skos:historyNote "WG Approval 18/06/2024"@en ;
    skos:prefLabel "has Loading Meter"@en .

epo:hasLotAwardCombination a owl:DatatypeProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "The contracting authority reserves the right to award contracts combining lots or groups of lots. Additional Information: This property contains information about the Lots concerned. This property is required by the regulation (EU)-2015-1986 (modeled in the TED Standard Forms). (epo:ProcedureTerm)"@en ;
    skos:historyNote "WG Approval 23/08/2022"@en ;
    skos:prefLabel "has Lot Award Combination"@en .

epo:hasLotReference a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Relation indicating the instance of the concept refers to a Lot."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "has Lot Reference"@en .

epo:hasLowestReceivedTenderValue a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Amount of the Tender with the lowest value. Additional Information The value must correspond to an admissible tender. For example, tenders compliant with the procurement document requirements, not having an abnormally low price or cost, etc."@en ;
    skos:historyNote "WG Approval 12/12/2019"@en ;
    skos:prefLabel "has Lowest Received Tender Value"@en .

epo:hasMainActivity a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "The principal sectoral area in which an organisation operates. Additional information: The activities associated with buyers are derived from the top level of the Classification of the functions of the government (COFOG) from the United Nations Statistics Division. The activities associated with buyer are derived from sectors explicitly falling within the sectoral directive (2014/25/EU Art. 8 - Art. 14)."@en ;
    skos:prefLabel "has Main Activity"@en .

epo:hasMainActivityDescription a owl:DatatypeProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Self-explanatory text about the Main Activity . Additional information: This field is used when the Main Activity is not available in the controlled list at-voc:main-activity-type . This is necessary in to cover data provided in the TED Standard Forms. It shall be deprecated in the future. (org:Organization)"@en ;
    skos:historyNote "WG Approval 06/09/2022"@en ;
    skos:prefLabel "has Main Activity Description"@en .

epo:hasMainClassification a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Relation indicating the main Common Procurement Vocabulary code."@en ;
    skos:prefLabel "has Main Classification"@en .

epo:hasMainFeature a owl:DatatypeProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Main features of the procedure and information about where the full rules for the procedure can be found. Additional Information: This information should be given when the procedure is not one of those mentioned in the procurement directives. This can be the case for example for concessions, for social and other specific services, and in case of voluntary publication of procurement procedures below the EU procurement thresholds. (epo:Procedure)"@en ;
    skos:prefLabel "has Main Feature"@en .

epo:hasMandateIdentifier a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "An unique identifier for referencing the direct debit mandate, assigned by the Payee."@en ;
    skos:historyNote "WG Approval 11/07/2024"@en ;
    skos:prefLabel "has Mandate Identifier"@en .

epo:hasManufacturerID a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "The manufacturer's identifier for the item."@en ;
    skos:prefLabel "has Manufacturer ID"@en .

epo:hasManufacturerItemID a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "The general identifier assigned to the concept as defined by the Manufacturer. ​"@en ;
    skos:historyNote "WG Approval 16/05/2023"@en ;
    skos:prefLabel "has Manufacturer Item ID"@en .

epo:hasMaskableProperty a owl:DatatypeProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Resource that has a hidden value. (epo:NonPublishedInformation)"@en ;
    skos:historyNote "WG approval 09/09/2025"@en ;
    skos:prefLabel "has Maskable Property"@en .

epo:hasMaximumFrameworkAgreementAwardedValue a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "The maximum value which can be spent through all the framework agreements announced in this notice, including options and renewals of contracts. Additional information: The value provided is a threshold value that implicity means that it cannot be exceeded however it may not be reached during the execution of a contract. The Framework Agreements in a CAN are to be traced back and added to provide this value."@en ;
    skos:editorialNote "Used by eForms BT-118"@en ;
    skos:historyNote "WG Approval 03/12/2019"@en ;
    skos:prefLabel "has Maximum Framework Agreement Awarded Value"@en .

epo:hasMaximumLotSubmissionAllowed a owl:DatatypeProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "The total number of lots for which one Tenderer can submit Tenders. Additional information: This field is used to complement the SubmissionTerms (which are at the Lot level) for the Procedure level which is covered by the regulation (EU)-2015-1986 (modeled in the TED Standard Forms). (epo:ProcedureTerm)"@en ;
    skos:historyNote "WG Approval 12/12/2018"@en ;
    skos:prefLabel "has Maximum Lot Submission Allowed"@en .

epo:hasMaximumMeasure a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Relation indicating the upper limit of the measure."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "has Maximum Measure"@en .

epo:hasMaximumNumberOfCandidates a owl:DatatypeProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Maximum number of candidates to be invited for the second stage of the procedure. (epo:MultipleStageProcedureTerm)"@en ;
    skos:historyNote "WG Approval 22/08/2019"@en ;
    skos:prefLabel "has Maximum Number Of Candidates"@en .

epo:hasMaximumNumberOfLotsToBeAwarded a owl:DatatypeProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "The maximum number of lots for which contract(s) can be awarded to one tenderer. Additional information: This field is used to complement the SubmissionTerms (which are at the Lot level) for the Procedure level which is covered by the regulation (EU)-2015-1986 (modeled in the TED Standard Forms). (epo:ProcedureTerm)"@en ;
    skos:historyNote "WG Approval 22/08/2019"@en ;
    skos:prefLabel "has Maximum Number Of Lots To Be Awarded"@en .

epo:hasMaximumNumberOfRenewals a owl:DatatypeProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "The maximum number of times the contract can be renewed. Additional Information By renewing, the buyer reserves the right (i.e. not an obligation) to renew the contract (i.e. extend its duration) without a new procurement procedure. For example, a contract may be valid for one year and the buyer may keep a possibility to renew it (e.g. once, twice) for another three months, if he is content with the services he received. PLEASE REVIEW THIS DEFINITION AGAIN WITH THE WORKING GROUP. It was originally taken from eForms. (epo:ContractTerm)"@en ;
    skos:prefLabel "has Maximum Number Of Renewals"@en .

epo:hasMaximumOrderQuantity a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "The maximum number of orderable units that can be ordered according to details provided in the catalogue line, such as price."@en ;
    skos:prefLabel "has Maximum Order Quantity"@en .

epo:hasMaximumParticipantsNumber a owl:DatatypeProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "The maximum number of participants in the framework agreement. Additional Information: Maximum number of tenderers who may be awarded a contract within the framework agreement. The number is a positive integer. (epo:FrameworkAgreementTerm)"@en ;
    skos:editorialNote "Used by eForms BT-113"@en ;
    skos:historyNote "WG Approval 05/02/2019"@en ;
    skos:prefLabel "has Maximum Participants Number"@en .

epo:hasMaximumShare a owl:DatatypeProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "The maximum proportion of something to be distributed. Additional Information: In the case of subcontracting the share may refer to the proportion of works, services or supplies being subcontracted. (epo:SubcontractTerm)"@en ;
    skos:historyNote "WG Approval 17/09/2019 "@en ;
    skos:prefLabel "has Maximum Share"@en .

epo:hasMaximumTemperature a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "The highest tolerated temperature."@en ;
    skos:historyNote "WG Approval 18/06/2024"@en ;
    skos:prefLabel "has Maximum Temperature"@en .

epo:hasMaximumValue a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Relation indicating the upper limit of the numerical quantity."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "has Maximum Value"@en .

epo:hasMeasure a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Relation indicating the unit used for stating the size."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "has Measure"@en .

epo:hasMediumTenderPerLots a owl:DatatypeProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Tenders from medium-sized enterprise. <u>Additional Information:</u> See Commission Recommendation 2003/361/EC. (epo:SubmissionStatisticalInformation)"@en ;
    skos:prefLabel "has Medium Tender Per Lots"@en .

epo:hasMember a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Relation indicating a part of the instance of the concept."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "has Member"@en .

epo:hasMinimumMeasure a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Relation indicating the lower limit of the measure."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "has Minimum Measure"@en .

epo:hasMinimumNumberOfCandidates a owl:DatatypeProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Minimum number of candidates to be invited for the second stage of the procedure. (epo:MultipleStageProcedureTerm)"@en ;
    skos:historyNote "WG Approval 22/08/2019"@en ;
    skos:prefLabel "has Minimum Number Of Candidates"@en .

epo:hasMinimumQuantityGuaranteedForDelivery a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "The minimum quantity of an item that is guaranteed by the seller to be delivered."@en ;
    skos:prefLabel "has Minimum Quantity Guaranteed For Delivery"@en .

epo:hasMinimumShare a owl:DatatypeProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "The minimum proportion of something to be distributed. Additional Information: In the case of subcontracting the share may refer to the proportion of works, services or supplies being subcontracted. (epo:SubcontractTerm)"@en ;
    skos:historyNote "WG Approval 17/09/2019"@en ;
    skos:prefLabel "has Minimum Share"@en .

epo:hasMinimumSubcontractorsProposedObligation a owl:DatatypeProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "The minimum percentage of the contract value that the contractor must subcontract. Additional information: This is used for the competitive procedure described in Title III of Directive 2009/81/EC. (epo:SubcontractTerm)"@en ;
    skos:historyNote "WG Approval 09/11/2021"@en ;
    skos:prefLabel "has Minimum Subcontractors Proposed Obligation"@en .

epo:hasMinimumTemperature a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "The lowest tolerated temperature."@en ;
    skos:historyNote "WG Approval 18/06/2024"@en ;
    skos:prefLabel "has Minimum Temperature"@en .

epo:hasMinimumValue a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Relation indicating the lower limit of the numerical quantity."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "has Minimum Value"@en .

epo:hasModificationJustification a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Explanation of why a contract was modified. The codelist to be used is at-voc:modification-justification which is available at http://publications.europa.eu/resource/dataset/modification-justification"@en ;
    skos:prefLabel "has Modification Justification"@en .

epo:hasNationalProcedureRules a owl:DatatypeProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "The resource identifier where the information about the national rules applicable to the procedure can be found. (epo:ProcedureTerm)"@en ;
    skos:historyNote "WG Approval 02/05/2024"@en ;
    skos:prefLabel "has National Procedure Rules"@en .

epo:hasNationality a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Relation indicating the country code to which the instance of the concept officially belongs to."@en ;
    skos:prefLabel "has Nationality"@en .

epo:hasNetAmount a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Relation indicating the Monetary Value exclusive of taxes and after substracting price discounts."@en ;
    skos:historyNote "WG approval 25/09/2025"@en ;
    skos:prefLabel "has Net Amount"@en .

epo:hasNetMonetaryValue a owl:ObjectProperty ;
