    skos:historyNote "WG Approval 18/06/2024"@en ;
    skos:prefLabel "has Net Volume"@en .

epo:hasNetWeight a owl:ObjectProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "The total mass of goods without the packaging."@en ;
    skos:historyNote "WG Approval 18/06/2024"@en ;
    skos:prefLabel "has Net Weight"@en .

