    skos:historyNote "WG Approval 06/09/2022"@en ;
    skos:prefLabel "has Non Awarded Contract Number"@en .

epo:hasNonAwardedContractTitle a owl:DatatypeProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "The title the contract would have had if it had been awarded. Additional information: This field is provided to support the data provided in the TED Standard Forms, and it should be discontinued in the future. (epo:LotAwardOutcome)"@en ;
    skos:historyNote "WG Approval 06/09/2022"@en ;
    skos:prefLabel "has Non Awarded Contract Title"@en .

epo:hasNonEEAReceivedTenders a owl:DatatypeProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "The amount of tenders received from economic operators in non-EEA countries. (epo:SubmissionStatisticalInformation)"@en ;
    skos:historyNote "WG Approval 12/12/2019"@en ;
    skos:prefLabel "has Non EEA Received Tenders"@en .

epo:hasNonEUReceivedTenders a owl:DatatypeProperty ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "The amount of tenders received from economic operators in non-EU countries. (epo:SubmissionStatisticalInformation)"@en ;
    skos:prefLabel "has Non EU Received Tenders"@en .

epo:hasNonElectronicSubmissionDescription a owl:DatatypeProperty ;
    rdfs:isDefinedBy epo:core ;
