    skos:definition "Overview of the Procurement Criteria."@en ;
    skos:historyNote "WG approval 19/03/2024"@en ;
    skos:prefLabel "Procurement Criteria Summary"@en .

epo:ProcurementCriterion a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf <http://data.europa.eu/m8g/Criterion> ;
    skos:definition "A criterion specific to Procurement."@en ;
    skos:historyNote "WG Approval 23/04/2020"@en ;
    skos:prefLabel "Procurement Criterion"@en .

epo:ProcurementElement a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Gathering class for critical/central elements in the Procurement Process. TODO: add definition Additional information: Alias: ProcurementComponent"@en ;
    skos:prefLabel "Procurement Element"@en .

epo:SelectionCriteriaSummary a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:QualificationCriteriaSummary ;
    skos:definition "Overview of the Selection Criteria."@en ;
    skos:historyNote "WG approval 19/03/2024"@en ;
    skos:prefLabel "Selection Criteria Summary"@en .

epo:StatisticalInformation a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:ContextDescription ;
    skos:definition "Statistical data on the Procedure and the Lot. Additional Information At the present time Procurement Procedures are not fully electronic. At a later date, information on the Tenders received could be inferred by the data in the eProcurement System. Therefore this class is temporal and should cease to exist in fully electronic Procurement. The need for its presence responds also to the alignment with the Regulation (EU) 2019/1780 (eForms). Attention will have to be paid in the future to possible inconsistencies derived from data placed in other classes and data held in the Statistical Information class; e.g. the TenderEvaluation class (see eEvaluation diagram) has the attribute admissibileTender indicator, which in case of being false, may enter in contradiction with the highest or lowest Tender value for that very same inadmissible Tender."@en ;
    skos:historyNote "WG Approval 12/12/2019"@en ;
    skos:prefLabel "Statistical Information"@en .

epo:StrategicProcurement a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Public Procurement that contributes to achieving pressing policy goals. Additional Information: Specific strategic goals could be, for example, Environmental Protection, innovation, job creation and the development of small and medium enterprises. The subclasses are given by the choices in BT-06 Strategic Procurement. Based on https://legalinstruments.oecd.org/en/instruments/OECD-LEGAL-0411 (see paragraph on \"background information\"."@en ;
    skos:editorialNote "Used by eForms BG-713"@en ;
    skos:historyNote "WG Approval 10/03/2020"@en ;
    skos:prefLabel "Strategic Procurement"@en .

epo:Technique a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Method used for conducting Procurement Procedures. Several Techniques can be combined in one single Procurement Procedure (e.g. eAuction can be carried out in a Framework Agreement or DPS)."@en ;
    skos:editorialNote "Used by eForms BG-706"@en ;
    skos:historyNote "WG Approval 19/09/2019"@en ;
    skos:prefLabel "Technique"@en .

epo:Contract a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "A voluntary, deliberate, and legally binding agreement between two or more competent parties."@en ;
    skos:historyNote "WG approval 19/03/2024"@en ;
    skos:prefLabel "Contract"@en .

epo:OfferingParty a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:AgentInRole ;
    skos:definition "The Role of an Agent that acts on the Economic Operator side during a Procurement Process. Additional information: As per the European Procurement Directives the notion of ‘Economic Operators’ should be interpreted in a broad manner so as to include any Persons and/or Entities which offer the execution of works, the supply of products or the provision of services on the market, irrespective of the legal form under which they have chosen to operate. Thus, firms, branches, subsidiaries, partnerships, cooperative societies, limited companies, universities, public or private, and other forms of entities than natural Persons should all fall within the notion of Economic Operator, whether or not they are ‘Legal Persons’ in all circumstances."@en ;
    skos:prefLabel "Offering Party"@en .

epo:ContextDescription a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "A description concerning a Procurement Object or a Notice in a specific Situation Context. Additional Information: The description has its own identity (+I) but is dependent (+D) on the concerned Entity. We say that ContextDescription *concerns* an Entity."@en ;
    skos:prefLabel "Context Description"@en .

epo:MaskableObject a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "Entity within the procurement data model whose visibility, accessibility, or disclosure may be conditionally restricted due to legal, confidentiality, or security requirements."@en ;
    skos:historyNote "WG approval 11/09/2025"@en ;
    skos:prefLabel "Maskable Object"@en .

epo:Term a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    skos:definition "A governing condition or stipulation."@en ;
    skos:prefLabel "Term"@en .

epo:AcquiringParty a owl:Class ;
    rdfs:isDefinedBy epo:core ;
    rdfs:subClassOf epo:AgentInRole ;
    skos:definition "The Role of an Agent that acts on the buying side of a Procurement Process."@en ;
    skos:prefLabel "Acquiring Party"@en .

epo:core a owl:Ontology ;
    rdfs:label "eProcurement Ontology - core"@en ;
    dcterms:created "2021-06-01"^^xsd:date ;
    dcterms:description "The eProcurement Ontology core describes the concepts and properties representing the European Public Procurement domain. The provision of these semantics offers the basis for a common understanding of the domain for all stakeholders ensuring the quality of data exchange and transparency. The ontology restrictions are published in a separate artefact."@en ;
