epo:DocumentaryEvidence a owl:Class ;
    rdfs:isDefinedBy epo:sub ;
    rdfs:subClassOf <http://data.europa.eu/m8g/Evidence> ;
    skos:definition "An Evidence submitted by an Economic Operator to prove compliance with legal, technical or financial requirements, or inapplicability of exclusion grounds in a Procurement Procedure."@en ;
    skos:historyNote "WG approval 16/09/2025"@en ;
    skos:prefLabel "Documentary Evidence"@en .

epo:ESPD a owl:Class ;
    rdfs:isDefinedBy epo:sub ;
    rdfs:subClassOf epo:Document ;
    skos:definition "A self-declaration of an economic operator, stating that it does not fall under the Exclusion Grounds and that it meets the Selection Criteria for a specific procurement."@en ;
    skos:historyNote "WG Approval 05/03/2024"@en ;
    skos:prefLabel "ESPD"@en .

epo:EvidenceInformation a owl:Class ;
    rdfs:isDefinedBy epo:sub ;
    rdfs:subClassOf epo:ContextDescription ;
    skos:definition "Information about a Certificate."@en ;
    skos:historyNote "WG Approval 12/03/2024"@en ;
    skos:prefLabel "Evidence Information"@en .

epo:LegalRepresentative a owl:Class ;
    rdfs:isDefinedBy epo:sub ;
    rdfs:subClassOf epo:AuxiliaryParty ;
    skos:definition "The Role of an Agent that can represent an Organization."@en ;
    skos:historyNote "WG Approval 05/03/2024"@en ;
    skos:prefLabel "Legal Representative"@en .

epo:Mandate a owl:Class ;
    rdfs:isDefinedBy epo:sub ;
    rdfs:subClassOf epo:Document ;
    skos:definition "An authorization to act as a representative of an Organization."@en ;
    skos:historyNote "WG Approval 05/03/2024"@en ;
    skos:prefLabel "Mandate"@en .

epo:OrganisationInformationSummary a owl:Class ;
    rdfs:isDefinedBy epo:sub ;
    rdfs:subClassOf epo:ContextDescription ;
    skos:definition "Information about the specific features or characteristics that qualify an economic operator to take part in a tendering process."@en ;
