epo:actsOnBehalfOf rdfs:domain epo:LegalRepresentative ;
    rdfs:range epo:OfferingParty .

epo:concernsOrganisation a owl:FunctionalProperty ;
    rdfs:domain epo:OrganisationInformationSummary ;
    rdfs:range org:Organization .

epo:coversAllSelectionCriteria rdfs:domain epo:EvidenceInformation ;
    rdfs:range xsd:boolean .

epo:hasPowerOfAttorney rdfs:domain epo:LegalRepresentative ;
