    rdfs:range epo:MonetaryValue .

epo:refersToApplicablePeriod rdfs:domain epo:Response ;
    rdfs:range time:Interval .

epo:relatesToESPDRequest rdfs:domain epo:ESPD ;
    rdfs:range epo:ESPDRequest .

epo:specifiesResponse rdfs:domain epo:ESPD ;
    rdfs:range epo:Response .

