    rdfs:domain epo:EvidenceInformation ;
    rdfs:range <http://data.europa.eu/m8g/Evidence> .

epo:EvidenceInformation rdfs:subClassOf [ a owl:Restriction ;
            owl:maxCardinality 1 ;
            owl:onProperty dcterms:description ],
        [ a owl:Restriction ;
            owl:maxCardinality 1 ;
            owl:onProperty epo:coversAllSelectionCriteria ],
        [ a owl:Restriction ;
            owl:cardinality 1 ;
            owl:onProperty epo:summarisesInformationAboutEvidence ] .

