epo:Response rdfs:subClassOf [ a owl:Restriction ;
            owl:maxCardinality 1 ;
            owl:onProperty epo:refersToApplicablePeriod ] .

epo:ESPD rdfs:subClassOf [ a owl:Restriction ;
            owl:minCardinality 1 ;
            owl:onProperty epo:specifiesResponse ],
        [ a owl:Restriction ;
            owl:maxCardinality 1 ;
            owl:onProperty epo:relatesToESPDRequest ] .

epo:OrganisationInformationSummary rdfs:subClassOf [ a owl:Restriction ;
            owl:maxCardinality 1 ;
            owl:onProperty epo:providesOrganisationFinancialCapability ],
        [ a owl:Restriction ;
            owl:maxCardinality 1 ;
            owl:onProperty epo:providesOrganisationCompletedTaskDescription ],
        [ a owl:Restriction ;
            owl:cardinality 1 ;
            owl:onProperty epo:concernsOrganisation ],
        [ a owl:Restriction ;
            owl:maxCardinality 1 ;
            owl:onProperty epo:providesOrganisationEmployeeQuantity ] .

[] a owl:AllDisjointClasses ;
    owl:members ( epo:ESPD epo:Mandate epo:PowerOfAttorney ) .

[] a owl:AllDisjointClasses ;
    owl:members ( epo:EvidenceInformation epo:OrganisationInformationSummary ) .

